6fba'),(4612,335,'template_blocks_1_features_3_img','63'),(4613,335,'_template_blocks_1_features_3_img','field_68b68f1946fb9'),(4614,335,'template_blocks_1_features_3_name','Актуальные исследования'),(4615,335,'_template_blocks_1_features_3_name','field_68b68f2646fba'),(4616,335,'template_blocks_1_features','4'),(4617,335,'_template_blocks_1_features','field_68b68f0746fb8'),(4618,335,'template_blocks_2_label','Основательницы'),(4619,335,'_template_blocks_2_label','field_68b692c93c01b'),(4620,335,'template_blocks_2_title','Привет! <span>Это основательницы клиники «Справиться Проще» </span>Карина Истомина и Наташа Каданцева.'),(4621,335,'_template_blocks_2_title','field_68b692e63c01c'),(4622,335,'template_blocks_2_text','Мы обе хорошо понимаем, что такое жить с ментальными трудностями: Карина столкнулась с ПРЛ и селфхармом, Наташа — с депрессией, а еще у нее СДВГ. И знаем, каково это, когда пациенту выписывают устаревшее лечение и относятся к нему с пренебрежением.\r\n\r\nПоэтому создали свою клинику — пространство, где нет места для стыда и вины, где к каждому относятся с теплом и пониманием. И все это — с опорой на доказательность.'),(4623,335,'_template_blocks_2_text','field_68b6932ced26d'),(4624,335,'template_blocks_2_page','159'),(4625,335,'_template_blocks_2_page','field_68b6933fed26e'),(4626,335,'template_blocks_3_title','Что вас беспокоит?'),(4627,335,'_template_blocks_3_title','field_68b9421db3429'),(4628,335,'template_blocks_3_shoose_tags','1'),(4629,335,'_template_blocks_3_shoose_tags','field_68b9424fb342c'),(4630,335,'template_blocks_3_tags','a:31:{i:0;s:2:\"14\";i:1;s:2:\"12\";i:2;s:2:\"13\";i:3;s:2:\"16\";i:4;s:2:\"15\";i:5;s:2:\"22\";i:6;s:2:\"30\";i:7;s:2:\"25\";i:8;s:2:\"40\";i:9;s:2:\"38\";i:10;s:2:\"43\";i:11;s:2:\"36\";i:12;s:2:\"39\";i:13;s:2:\"31\";i:14;s:2:\"42\";i:15;s:2:\"27\";i:16;s:2:\"41\";i:17;s:2:\"47\";i:18;s:2:\"29\";i:19;s:2:\"44\";i:20;s:2:\"34\";i:21;s:2:\"28\";i:22;s:2:\"24\";i:23;s:2:\"45\";i:24;s:2:\"26\";i:25;s:2:\"37\";i:26;s:2: