";i:9547;}s:12:\"medium_large\";a:5:{s:4:\"file\";s:23:\"IMG_4228-2-768x1148.jpg\";s:5:\"width\";i:768;s:6:\"height\";i:1148;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:95966;}s:9:\"1536x1536\";a:5:{s:4:\"file\";s:24:\"IMG_4228-2-1027x1536.jpg\";s:5:\"width\";i:1027;s:6:\"height\";i:1536;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:209577;}s:9:\"2048x2048\";a:5:{s:4:\"file\";s:24:\"IMG_4228-2-1370x2048.jpg\";s:5:\"width\";i:1370;s:6:\"height\";i:2048;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:471555;}s:14:\"doctor-article\";a:5:{s:4:\"file\";s:22:\"IMG_4228-2-438x246.jpg\";s:5:\"width\";i:438;s:6:\"height\";i:246;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:9547;}s:6:\"doctor\";a:5:{s:4:\"file\";s:22:\"IMG_4228-2-580x720.jpg\";s:5:\"width\";i:580;s:6:\"height\";i:720;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:40829;}s:6:\"avatar\";a:5:{s:4:\"file\";s:22:\"IMG_4228-2-120x120.jpg\";s:5:\"width\";i:120;s:6:\"height\";i:120;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:2849;}s:12:\"about_slider\";a:5:{s:4:\"file\";s:22:\"IMG_4228-2-485x646.jpg\";s:5:\"width\";i:485;s:6:\"height\";i:646;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:27431;}s:13:\"about_gallery\";a:5:{s:4:\"file\";s:22:\"IMG_4228-2-684x386.jpg\";s:5:\"width\";i:684;s:6:\"height\";i:386;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:25570;}}s:10:\"image_meta\";a:12:{s:8:\"aperture\";s:1:\"0\";s:6:\"credit\";s:0:\"\";s:6:\"camera\";s:0:\"\";s:7:\"caption\";s:0:\"\";s:17:\"created_timestamp\";s:1:\"0\";s:9:\"copyright\";s:0:\"\";s:12:\"focal_length\";s:1:\"0\";s:3:\"iso\";s:1:\"0\";s:13:\"shutter_speed\";s:1:\"0\";s:5:\"title\";s:0:\"\";s:11:\"orientation\";s:1:\"1\";s:8:\"keywords\";a:0:{}}s:14:\"original_image\";s:14:\"IMG_4228-2.jpg\";}'),(4834,383,'email','clinic@handlingbetter.ru'),(4835,383,'_email','field_68b99a437efbf'),(4836,383,'details_name','ООО «Справиться Проще»'),(4837,383,'_details_name','field_68b99a8f7efc1'),(4838,383,'details_ogrn','ОГРН: 1247700690808'),(4839,383,'_details_ogrn','field_68b99aa77efc2'),(4840,383,'details_inn','ИНН: 9701299000'),(4841,383,'_details_inn','field_68b99abd7efc3'),(4842,383,'details_kpp','КПП: 770101001'),(4843,383,'_details_kpp','field_68b99aca7efc4'),(4844,383,'details',''),(4845,383,'_details','field_68b99a667efc0'),(4846,383,'faq_0_q','Как добраться на автомобиле'),(4847,383,'_faq_0_q','field_68b99b6dd3845'),(4848,383,'faq_0_a','<span style=\"font-weight: 400;\">Сверните с Третьего транспортного кольца на Малую Почтовую улицу. Проехав через Лефортовскую площадь, поверните на Старокирочный переулок. Клиника расположена на его пересечении с Бауманской улицей.</span>'),(4849,383,'_faq_0_a','field_68b99b77d3846'),(4850,383,'faq_1_q','Куда припарковать авто'),(4851,383,'_faq_1_q','field_68b99b6dd3845'),(4852,383,'faq_1_a','<span style=\"font-weight: 400;\">Рядом с клиникой расположены две большие городские парковки:</span>\r\n<ul>\r\n 	<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400;\">Парковка на Бауманской улице (платная, почасовая оплата).</span></li>\r\n 	<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400;\">Парковка в Старокирочном переулке (в 2 минутах пешком от клиники).</span></li>\r\n</ul>\r\n<b>Время работы парковок:</b><span style=\"font-weight: 400;\"> ежедневно, круглосуточно.</span>\r\n\r\n<b>Стоимость:</b><span style=\"font-weight: 400;\"> согласно тарифам Москвы.</span>\r\n\r\n<!-- notionvc: c5ead001-7581-48e2-b0b8-66b2aa792327 -->'),(4853,383,'_faq_1_a','field_68b99b77d3846'),(4854,383,'faq_2_q','Как добраться на метро'),(4855,383,'_faq_2_q','field_68b99b6dd3845'),(4856,383,'faq_2_a','<b>От станции метро «Бауманская», пешком — 5–7 минут </b>\r\n\r\n<span style=\"font-weight: 400;\">Выйдите из метро через выход №1. Поверните налево и пройдите по Бауманской улице вдоль трамвайных путей около 200 метров. </span>\r\n\r\n<span style=\"font-weight: 400;\">Клиника находится в доме №47 по левой стороне улицы. Не доходя до него, сверните между домом и парковкой, и пройдите до конца. После поворота направо, вы окажетесь рядом с входом в клинику.</span>'),(4857,383,'_faq_2_a','field_68b99b77d3846'),(4858,383,'faq','3'),(4859,383,'_faq','field_68b99b64d3844'),(4860,372,'template_blocks_0_title','Клиника психиатрии\r\nи неврологии нового уровня'),(4861,372,'_template_blocks_0_title','field_68b67cd690831'),(4862,372,'template_blocks_0_link','/doctors/'),(4863,372,'_template_blocks_0_link','field_68b67d3890832'),(4864,372,'template_blocks_0_desc','С опорой на науку и бережным отношением к каждому'),(4865,372,'_template_blocks_0_desc','field_68b67d6390833'),(4866,372,'template_blocks_0_img','298'),(4867,372,'_template_blocks_0_img','field_68b67d7b90834'),(4868,372,'template_blocks','a:8:{i:0;s:4:\"main\";i:1;s:8:\"features\";i:2;s:5:\"about\";i:3;s:4:\"tags\";i:4;s:4:\"spec\";i:5;s:15:\"second_features\";i:6;s:9:\"physician\";i:7;s:3:\"faq\";}'),(4869,372,'_template_blocks','field_68b67c31c6619'),(4870,372,'template_blocks_1_features_0_img','60'),(4871,372,'_template_blocks_1_features_0_img','field_68b68f1946fb9'),(4872,372,'template_blocks_1_features_0_name','Только доказательные подходы'),(4873,372,'_template_blocks_1_features_0_name','field_68b68f2646fba'),(4874,372,'template_blocks_1_features_1_img','61'),(4875,372,'_template_blocks_1_features_1_img','field_68b68f1946fb9'),(4876,372,'template_blocks_1_features_1_name','Строгий отбор специалистов'),(4877,372,'_template_blocks_1_features_1_name','field_68b68f2646fba'),(4878,372,'template_blocks_1_features_2_img','62'),(4879,372,'_template_blocks_1_features_2_img','field_68b68f1946fb9'),(4880,372,'template_blocks_1_features_2_name','Уважение к каждому пациенту'),(4881,372,'_template_blocks_1_features_2_name','field_68b68f2646fba'),(4882,372,'template_blocks_1_features_3_img','63'),(4883,372,'_template_blocks_1_features_3_img','field_68b68f1946fb9'),(4884,372,'template_blocks_1_f