i:6;s:9:\"physician\";i:7;s:3:\"faq\";}'),(8556,516,'_template_blocks','field_68b67c31c6619'),(8557,516,'template_blocks_1_features_0_img','60'),(8558,516,'_template_blocks_1_features_0_img','field_68b68f1946fb9'),(8559,516,'template_blocks_1_features_0_name','Только доказательные подходы'),(8560,516,'_template_blocks_1_features_0_name','field_68b68f2646fba'),(8561,516,'template_blocks_1_features_1_img','61'),(8562,516,'_template_blocks_1_features_1_img','field_68b68f1946fb9'),(8563,516,'template_blocks_1_features_1_name','Строгий отбор специалистов'),(8564,516,'_template_blocks_1_features_1_name','field_68b68f2646fba'),(8565,516,'template_blocks_1_features_2_img','62'),(8566,516,'_template_blocks_1_features_2_img','field_68b68f1946fb9'),(8567,516,'template_blocks_1_features_2_name','Уважение к каждому пациенту'),(8568,516,'_template_blocks_1_features_2_name','field_68b68f2646fba'),(8569,516,'template_blocks_1_features_3_img','63'),(8570,516,'_template_blocks_1_features_3_img','field_68b68f1946fb9'),(8571,516,'template_blocks_1_features_3_name','Актуальные исследования'),(8572,516,'_template_blocks_1_features_3_name','field_68b68f2646fba'),(8573,516,'template_blocks_1_features','4'),(8574,516,'_template_blocks_1_features','field_68b68f0746fb8'),(8575,516,'template_blocks_2_label','Основательницы клиники «Справиться Проще»'),(8576,516,'_template_blocks_2_label','field_68b692c93c01b'),(8577,516,'template_blocks_2_title','Привет! Это Карина Истомина и&nbsp;Наташа Каданцева.'),(8578,516,'_template_blocks_2_title','field_68b692e63c01c'),(8579,516,'template_blocks_2_text','Мы обе хорошо понимаем, что такое жить с ментальными трудностями: Карина столкнулась с ПРЛ и селфхармом, Наташа — с депрессией, а еще у нее СДВГ. И знаем, каково это, когда пациенту выписывают устаревшее лечение и относятся к нему с пренебрежением.\r\n\r\nПоэтому создали свою клинику: пространство, где нет места для стыда и вины, где к каждому относятся с теплом и пониманием. И все это — с опорой на доказательность.'),(8580,516,'_template_blocks_2_text','field_68b6932ced26d'),(8581,516,'template_blocks_2_page','159'),(8582,516,'_template_blocks_2_page','field_68b6933fed26e'),(8583,516,'template_blocks_3_title','Что вас беспокоит?'),(8584,516,'_template_blocks_3_title','field_68b9421db3429'),(8585,516,'template_blocks_3_shoose_tags','1'),(8586,516,'_template_blocks_3_shoose_tags','field_68b9424fb342c'),(8587,516,'template_blocks_3_tags','a:31:{i:0;s:2:\"14\";i:1;s:2:\"12\";i:2;s:2:\"13\";i:3;s:2:\"16\";i:4;s:2:\"15\";i:5;s:2:\"22\";i:6;s:2:\"30\";i:7;s:2:\"25\";i:8;s:2:\"40\";i:9;s:2:\"38\";i:10;s:2:\"43\";i:11;s:2:\"36\";i:12;s:2:\"39\";i:13;s:2:\"31\";i:14;s:2:\"42\";i:15;s:2:\"27\";i:16;s:2:\"41\";i:17;s:2:\"47\";i:18;s:2:\"29\";i:19;s:2:\"44\";i:20;s:2:\"34\";i:21;s:2:\"28\";i:22;s:2:\"24\";i:23;s:2:\"45\";i:24;s:2:\"26\";i:25;s:2:\"37\";i:26;s:2:\"46\";i:27;s:2:\"33\";i:28;s:2:\"32\";i:29;s:2:\"35\";i:30;s:2:\"23\";}'),(8588,516,'_template_blocks_3_tags','field_68b94277b342d'),(8589,516,'template_blocks_4_title','«Справиться Проще» — научно-популярный проект о&nbsp;ментальном здоровье'),(8590,516,'_template_blocks_4_title','field_68b946ac51456'),(8591,516,'template_blocks_4_desc','С&nbsp;2021 года вместе с&nbsp;гостями, психотерапевтами и&nbsp;врачами из&nbsp;наших выпусков снимаем стигму с&nbsp;психических расстройств. Если в&nbsp;программе мы&nbsp;рассказываем о&nbsp;способах помощи, то&nbsp;в&nbsp;клинике&nbsp;&mdash; оказываем&nbsp;ее.'),(8592,516,'_template_blocks_4_desc','field_68b946d151459'),(8593,516,'template_blocks_4_doctors','a:6:{i:0;s:3:\"255\";i:1;s:3:\"331\";i:2;s:3:\"327\";i:3;s:3:\"329\";i:4;s:3:\"307\";i:5;s:3:\"309\";}'),(8594,516,'_template_blocks_4_doctors','field_68b946f45145a'),(8595,516,'template_blocks_5_title','Каждый из наших специалистов'),(8596,516,'_template_blocks_5_title','field_68b97b1616ba6'),(8597,516,'template_blocks_5_features_0_img','111'),(8598,516,'_template_blocks_5_features_0_img','field_68b97a6916ba4'),(8599,516,'tem