s_4_title','field_68b97b1616ba6'),(11754,658,'template_blocks_4_features_0_img','593'),(11755,658,'_template_blocks_4_features_0_img','field_68b97a6916ba4'),(11756,658,'template_blocks_4_features_0_name','Долгосрочное обучение'),(11757,658,'_template_blocks_4_features_0_name','field_68b97a6916ba5'),(11758,658,'template_blocks_4_features_0_desc','Все наши психологи постоянно повышают квалификацию и имеют высшее образование'),(11759,658,'_template_blocks_4_features_0_desc','field_68b97b3016ba7'),(11760,658,'template_blocks_4_features_1_img','594'),(11761,658,'_template_blocks_4_features_1_img','field_68b97a6916ba4'),(11762,658,'template_blocks_4_features_1_name','Супервизии и интервизии'),(11763,658,'_template_blocks_4_features_1_name','field_68b97a6916ba5'),(11764,658,'template_blocks_4_features_1_desc','Наши специалисты не остаются наедине с проблемными вопросами и имеют поддержку коллег'),(11765,658,'_template_blocks_4_features_1_desc','field_68b97b3016ba7'),(11766,658,'template_blocks_4_features_2_img','595'),(11767,658,'_template_blocks_4_features_2_img','field_68b97a6916ba4'),(11768,658,'template_blocks_4_features_2_name','Этика'),(11769,658,'_template_blocks_4_features_2_name','field_68b97a6916ba5'),(11770,658,'template_blocks_4_features_2_desc','Все наши специалисты прошли тестирование на приверженность этическим стандартам и придерживаются их в своей работе'),(11771,658,'_template_blocks_4_features_2_desc','field_68b97b3016ba7'),(11772,658,'template_blocks_4_features_3_img','596'),(11773,658,'_template_blocks_4_features_3_img','field_68b97a6916ba4'),(11774,658,'template_blocks_4_features_3_name','Контроль качества'),(11775,658,'_template_blocks_4_features_3_name','field_68b97a6916ba5'),(11776,658,'template_blocks_4_features_3_desc','Собираем обратную связь по работе специалистов, а все новые психологи проходят полугодовую стажировку'),(11777,658,'_template_blocks_4_features_3_desc','field_68b97b3016ba7'),(11778,658,'template_blocks_4_features','4'),(11779,658,'_template_blocks_4_features','field_68b97a6916ba3'),(11780,658,'template_blocks_5_title','Подберите психолога по запросу'),(11781,658,'_template_blocks_5_title','field_68b946ac51456'),(11782,658,'template_blocks_5_desc',''),(11783,658,'_template_blocks_5_desc','field_68b946d151459'),(11784,658,'template_blocks_5_doctors','a:1:{i:0;s:3:\"638\";}'),(11785,658,'_template_blocks_5_doctors','field_68b946f45145a'),(11786,658,'template_blocks_7_label','Основательницы клиники «Справиться Проще»'),(11787,658,'_template_blocks_7_label','field_68b692c93c01b'),(11788,658,'template_blocks_7_title','Привет! Это Карина Истомина и&nbsp;Наташа Каданцева.'),(11789,658,'_template_blocks_7_title','field_68b692e63c01c'),(11790,658,'template_blocks_7_text','Мы обе хорошо понимаем, что такое жить с ментальными трудностями: Карина столкнулась с ПРЛ и селфхармом, Наташа — с депрессией, а еще у нее СДВГ. И знаем, каково это, когда пациенту выписывают устаревшее лечение и относятся к нему с пренебрежением.\r\n\r\nПоэтому создали свою клинику: пространство, где нет места для стыда и вины, где к каждому относятся с теплом и пониманием. И все это — с опорой на доказательность.'),(11791,658,'_template_blocks_7_text','field_68b6932ced26d'),(11792,658,'template_blocks_7_page','159'),(11793,658,'_template_blocks_7_page','field_68b6933fed26e'),(11794,658,'template_blocks_7_karina_link','https://t.me/istominakarina'),(11795,658,'_template_blocks_7_karina_link','field_68b9f1a1a1011'),(11796,658,'template_blocks_7_natasha_link','https://t.me/hadeout'),(11797,658,'_template_blocks_7_natasha_link','field_68b9f1b9a1012'),(11798,658,'template_blocks_7_more_link','https://handlingbetter.ru/'),(11799,658,'_template_blocks_7_more_link','field_68b9f1d2a1013'),(11800,658,'template_blocks_2_link_1','https://center.handlingbetter.ru/kognitivno-povedencheskaya-terapiya/'),(11801,658,'_template_blocks_2_link_1','field_68b9f2b07faa2'),(11802,658,'template_blocks_2_link_2','https://center.handlingbetter.ru/terapiya-prinyatiya-i-otvetstvennosti/'),(11803,658,'_template_blocks_2_link_2','field_68b9f2c07faa3'),(11804,658,'template_blocks_2_link_3','https://center.handlingbetter.ru/dialekticheskaya-povedencheskaya-terapiya/'),(11805,658,'_template_blocks_2_link_3','field_68b9f2d07faa4'),(11806,658,'template_blocks_2_link_4','https://center.handlingbetter.ru/kognitivno-protsessualnaya-terapiya/'),(11807,658,'_template_blocks_2_link_4','field_68b9f2e07faa5'),(11808,658,'template_blocks_2_link_5','https://clinic.handlingbetter.ru/5'),(11809,658,'_template_blocks_2_link_5','field_68b9f2f07faa6'),(11810,658,'template_blocks_2_link_6','https://clinic.handlingbetter.ru/6'),(11811,658,'_template_blocks_2_link_6','field_68b9f3007faa7'),(11812,658,'template_blocks_2_link_7','https://clinic.handlingbetter.ru/7'),(11813,658,'_template_blocks_2_link_7','field_68b9f3107faa8'),(11814,658,'template_blocks_2_link_8','https://center.handlingbetter.ru/psihologam/'),(11815,658,'_template_blocks_2_link_8','field_68b9f3207faa9'),(11816,663,'_edit_last','1'),(11817,663,'_edit_lock','1770542591:1'),(11818,664,'_wp_attached_file','2026/02/REBT-terapy.jpg'),(11819,664,'_wp_attachment_metadata','a:6:{s:5:\"width\";i:1300;s:6:\"height\";i:600;s:4:\"file\";s:23:\"2026/02/REBT-terapy.jpg\";s:8:\"filesize\";i:43249;s:5:\"sizes\";a:9:{s:6:\"medium\";a:5:{s:4:\"file\";s:23:\"REBT-terapy-684x316.jpg\";s:5:\"width\";i:684;s:6:\"height\";i:316;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:16690;}s:5:\"large\";a:5:{s:4:\"file\";s:24:\"REBT-terapy-1024x473.jpg\";s:5:\"width\";i:1024;s:6:\"height\";i:473;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:30973;}s:9:\"thumbnail\";a:5:{s:4:\"file\";s:23:\"REBT-terapy-438x246.jpg\";s:5:\"width\";i:438;s:6:\"height\";i:246;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:10012;}s:12:\"medium_large\";a:5:{s:4:\"file\";s:23:\"REBT-terapy-768x354.jpg\";s:5:\"width\";i:768;s:6:\"height\";i:354;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:19786;}s:14:\"doctor-article\";a:5:{s:4:\"file\";s:23:\"REBT-terapy-438x246.jpg\";s:5:\"width\";i:438;s:6:\"height\";i:246;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:10012;}s:6:\"doctor\";a:5:{s:4:\"file\";s:23:\"REBT-terapy-580x600.jpg\";s:5:\"width\";i:580;s:6:\"height\";i:600;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:19406;}s:6:\"avatar\";a:5:{s:4:\"file\";s:23:\"REBT-terapy-120x120.jpg\";s:5:\"width\";i:120;s:6:\"height\";i:120;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:1951;}s:12:\"about_slider\";a:5:{s:4:\"file\";s:23:\"REBT-terapy-485x600.jpg\";s:5:\"width\";i:485;s:6:\"height\";i:600;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:16738;}s:13:\"about_gallery\";a:5:{s:4:\"file\";s:23:\"REBT-terapy-684x386.jpg\";s:5:\"width\";i:684;s:6:\"height\";i:386;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:19988;}}s:10:\"image_meta\";a:12:{s:8:\"aperture\";s:1:\"0\";s:6:\"credit\";s:0:\"\";s:6:\"camera\";s:0:\"\";s:7:\"caption\";s:0:\"\";s:17:\"created_timestamp\";s:1:\"0\";s:9:\"copyright\";s:0:\"\";s:12:\"focal_length\";s:1:\"0\";s:3:\"iso\";s:1:\"0\";s:13:\"shutter_speed\";s:1:\"0\";s:5:\"title\";s:0:\"\";s:11:\"orientation\";s:1:\"0\";s:8:\"keywords\";a:0:{}}}'),(11821,663,'_wp_old_slug','racionalno-emocionalno-povedencheskaya-terapiya'),(11822,663,'header_h1','Рационально-эмоционально-поведенческая терапия (РЭПТ) '),(11823,663,'_header_h1','field_68ba8268fea8a'),(11824,663,'header_lead','Рационально-эмоционально-поведенческая терапия (РЭПТ) — одно из направлений когнитивно-поведенческой терапии. Это подход, который фокусируется на изменении иррациональных убеждений и дисфункциональных, не помогающих решению проблемы, а также эмоций, чтобы сформировать у человека новые эффективные стратегии поведения.'),(11825,663,'_header_lead','field_68ba82a3fea8b'),(11826,663,'specialty','59'),(11827,663,'_specialty','field_68baddbb0ca88'),(11828,663,'blocks_0_text','Другие названия подхода — «рационально-эмотивная терапия», «рационально-эмоциональная терапия» и «рационально-поведенческая терапия».\r\n<h2>Кому подойдет</h2>\r\nРЭПТ подходит для работы с самыми разными эмоциональными и поведенческими проблемами, которые доставляют человеку дискомфорт и влияют на качество его жизни.\r\n<h2>С чем обращаться к РЭПТ-специалисту:</h2>\r\n<ul>\r\n 	<li>тревога;</li>\r\n 	<li>депрессия;</li>\r\n 	<li>выгорание;</li>\r\n 	<li>прокрастинация;</li>\r\n 	<li>зависимое поведение;</li>\r\n 	<li>социальная тревожность;</li>\r\n 	<li>проблемы с самооценкой и ассертивностью (отстаиванием своих прав);</li>\r\n 	<li>проблемы с контролем гнева.</li>\r\n</ul>\r\nКакая бы проблема или психологическая травма не беспокоила клиента, на консультациях с терапевтом он будет учиться вырабатывать у себя новые конструктивные убеждения и эффективное поведение.\r\n<h2>Особенности рационально-эмоционально-поведенческой терапии</h2>\r\nОсновная идея рационально-эмотивно-поведенческой терапии — убеждения, эмоции и поведение человека взаимосвязаны, и изменение одного из этих аспектов ведет к изменению других. Значит, если поменять мышление, поменяются и эмоциональные реакции, и поведение.\r\n\r\nОтражается эта идея в модели ABC:\r\n<strong>A (активирующее событие) → B (внутренние установки) → C (последствия)</strong>\r\n\r\nЗдесь <strong>активирующее событие</strong> — это ситуация, чувства или мысли, которые запускают реакцию. Человек интерпретирует событие через призму своих <strong>внутренних убеждений</strong>. Они в свою очередь вызывают <strong>последствия</strong> — эмоции, которые толкают к какому-либо поведению, мыслям, импульсам.\r\n\r\nНапример, ситуация — приближение экзаменов. Если у студента есть убеждение, что он завалит экзамены, вся его жизнь разрушится, то он может ощущать сильную тревогу. А студент, уверенный, что его в любом случае ждет пересдача, будет спокоен.\r\n\r\nМы всё воспринимаем по-разному, через призму наших убеждений, ценностей, предпочтений и прошлого опыта. Поэтому и реакции у нас индивидуальные.\r\n\r\n<strong>Определить убеждения клиента и связать их с, А и С помогает РЭПТ-специалист.</strong>\r\n\r\nСами убеждения делятся на <strong>рациональные</strong> и <strong>иррациональные</strong>. Первые реалистичны и помогают достигать целей, а вторые искажают реальность и мешают добиваться задуманного. Рациональные убеждения ведут к продуктивному поведению, иррациональные — к разрушающему, мешающему разрешению проблемы.\r\n\r\nВ РЭПТ-терапии специалисты выделяют четыре вида иррациональных убеждений:\r\n<ol>\r\n 	<li><strong>Требовательность / Долженствование</strong> — ожидание, что все должно быть так, как человек задумал. «Я должен всё делать идеально…», «другие должны хорошо со мной обращаться…»;</li>\r\n 	<li><strong>Катастрофизация</strong> — преувеличение возможных негативных последствий ситуации и ожидание худшего;</li>\r\n 	<li><strong>Нетерпимость фрустрации</strong> — уверенность, что жизнь должна быть легкой и приятной; неспособность переносить дискомфорт;</li>\r\n 	<li><strong>Глобальная оценка</strong> — оценивание себя и других. Уверенность, что некоторые люди менее ценны, чем другие.</li>\r\n</ol>\r\nВ РЭПТ психолог с клиентом работают над тем, чтобы выявить эти иррациональные убеждения и превратить их в рациональные. Например, трансформировать «я должен…» в «было бы неплохо…», а «это полная катастрофа» в «да, это неприятно, но это не конец света».'),(11829,663,'_blocks_0_text','field_68ba82d4fea8e'),(11830,663,'blocks_1_img','664'),(11831,663,'_blocks_1_img','field_68ba8338fea91'),(11832,663,'blocks_1_text','Исследования об эффективности РЭПТ'),(11833,663,'_blocks_1_text','field_68ba8349fea92'),(11834,663,'blocks_1_link','https://onlinelibrary.wiley.com/doi/10.1002/jclp.22514'),(11835,663,'_blocks_1_link','field_68ba837dfea93'),(11836,663,'blocks_2_text','<h2>Как проходит РЭПТ-терапия</h2>\r\nГлавная задача РЭПТ — научить клиента самостоятельно вырабатывать у себя новое поведение. По сути, стать терапевтом самому себе: уметь анализировать свои проблемы, выявлять иррациональные убеждения и работать с ними.\r\n\r\nНа первых встречах терапевт вместе с клиентом определяет цель и результат, к которому планируют прийти к концу терапии. Затем терапевт помогает клиенту осознать и трансформировать его иррациональные убеждения.\r\n\r\nРациональная терапия ориентирована на анализ настоящего, а не прошлого. Упор на терапии будет делаться на то, что сейчас мешает человеку. Детский опыт анализируется только в том случае, если он в настоящее время вызывает у клиента болезненные переживания.\r\n\r\nЧтобы закрепить изменения иррациональных убеждений и научиться применять новое поведение вне кабинета психолога, клиент в РЭПТ выполняет различные домашние задания: заполняет дневник самонаблюдения, делает упражнения с использованием воображения и многое другое.\r\n\r\nРЭПТ — <strong>краткосрочный подход.</strong> Иногда достаточно одной-двух консультаций, а в сложных случаях может доходить до двадцати. В среднем для достижения результата требуется пять-восемь встреч.\r\n<h2>К кому обратиться за помощью</h2>\r\nЕсли вы хотите найти у себя иррациональные убеждения, которые мешают качеству вашей жизни, и выработать у себя новые эффективные стратегии поведения, вам подойдет помощь РЭПТ-психолога центра «Справиться Проще».'),(11837,663,'_blocks_2_text','field_68ba82d4fea8e'),(11838,663,'blocks','a:3:{i:0;s:7:\"content\";i:1;s:5:\"promo\";i:2;s:7:\"content\";}'),(11839,663,'_blocks','field_68ba81fef8137'),(11840,663,'_yoast_wpseo_primary_category',''),(11841,663,'_yoast_wpseo_title','Рационально-эмоциональная поведенческая терапия (РЭПТ): что это, кому подходит, особенности метода | Справиться Проще'),(11842,663,'_yoast_wpseo_metadesc','Сертифицированные РЭПТ-психологи по рационально-эмоциональной поведенческой терапии. Запись и консультации в Telegram, WhatsApp или через форму обратной связи.'),(11843,663,'_yoast_wpseo_content_score','90'),(11844,663,'_yoast_wpseo_estimated-reading-time-minutes','0'),(11845,663,'_post_views','7'),(11846,665,'header_h1','Рационально-эмоционально-поведенческая терапия (РЭПТ) '),(11847,665,'_header_h1','field_68ba8268fea8a'),(11848,665,'header_lead','Рационально-эмоционально-поведенческая терапия (РЭПТ) — одно из направлений когнитивно-поведенческой терапии. Это подход, который фокусируется на изменении иррациональных убеждений и дисфункциональных, не помогающих решению проблемы, а также эмоций, чтобы сформировать у человека новые эффективные стратегии поведения.'),(11849,665,'_header_lead','field_68ba82a3fea8b'),(11850,665,'specialty','59'),(11851,665,'_specialty','field_68baddbb0ca88'),(11852,665,'blocks_0_text','Другие названия подхода — «рационально-эмотивная терапия», «рационально-эмоциональная терапия» и «рационально-поведенческая терапия».\r\n<h2 class=\"t-redactor__h2\">Кому подойдет</h2>\r\n<div class=\"t-redactor__text\">РЭПТ подходит для работы с самыми разными эмоциональными и поведенческими проблемами, которые доставляют человеку дискомфорт и влияют на качество его жизни.</div>\r\n<h2 class=\"t-redactor__h2\">С чем обращаться к РЭПТ-специалисту:</h2>\r\n<div class=\"t-redactor__text\">\r\n<ul>\r\n 	<li data-list=\"bullet\">тревога;</li>\r\n 	<li data-list=\"bullet\">депрессия;</li>\r\n 	<li data-list=\"bullet\">выгорание;</li>\r\n 	<li data-list=\"bullet\">прокрастинация;</li>\r\n 	<li data-list=\"bullet\">зависимое поведение;</li>\r\n 	<li data-list=\"bullet\">социальная тревожность;</li>\r\n 	<li data-list=\"bullet\">проблемы с самооценкой и ассертивностью (отстаиванием своих прав);</li>\r\n 	<li data-list=\"bullet\">проблемы с контролем гнева.</li>\r\n</ul>\r\nКакая бы проблема или психологическая травма не беспокоила клиента, на консультациях с терапевтом он будет учиться вырабатывать у себя новые конструктивные убеждения и эффективное поведение.\r\n\r\n</div>\r\n<h2 class=\"t-redactor__h2\">Особенности рационально-эмоционально-поведенческой терапии</h2>\r\n<div>\r\n<div class=\"t-redactor__text\">Основная идея рационально-эмотивно-поведенческой терапии — убеждения, эмоции и поведение человека взаимосвязаны, и изменение одного из этих аспектов ведет к изменению других. Значит, если поменять мышление, поменяются и эмоциональные реакции, и поведение.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">Отражается эта идея в модели ABC:\r\n<strong>A (активирующее событие) → B (внутренние установки) → C (последствия)</strong></div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">Здесь активирующее событие — это ситуация, чувства или мысли, которые запускают реакцию. Человек интерпретирует событие через призму своих внутренних убеждений. Они в свою очередь вызывают последствия — эмоции, которые толкают к какому-либо поведению, мыслям, импульсам.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">Например, ситуация — приближение экзаменов. Если у студента есть убеждение, что он завалит экзамены, вся его жизнь разрушится, то он может ощущать сильную тревогу. А студент, уверенный, что его в любом случае ждет пересдача, будет спокоен.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">Мы всё воспринимаем по-разному, через призму наших убеждений, ценностей, предпочтений и прошлого опыта. Поэтому и реакции у нас индивидуальные.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\"><strong>Определить убеждения клиента и связать их с, А и С помогает РЭПТ-специалист.</strong></div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">Сами убеждения делятся на рациональные и иррациональные. Первые реалистичны и помогают достигать целей, а вторые искажают реальность и мешают добиваться задуманного. Рациональные убеждения ведут к продуктивному поведению, иррациональные — к разрушающему, мешающему разрешению проблемы.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">В РЭПТ-терапии специалисты выделяют четыре вида иррациональных убеждений:</div>\r\n<div class=\"t-redactor__text\">\r\n<ol>\r\n 	<li data-list=\"ordered\"><strong>Требовательность / Долженствование</strong> — ожидание, что все должно быть так, как человек задумал. «Я должен всё делать идеально…», «другие должны хорошо со мной обращаться…»;</li>\r\n 	<li data-list=\"ordered\"><strong>Катастрофизация</strong> — преувеличение возможных негативных последствий ситуации и ожидание худшего;</li>\r\n 	<li data-list=\"ordered\"><strong>Нетерпимость фрустрации</strong> — уверенность, что жизнь должна быть легкой и приятной; неспособность переносить дискомфорт;</li>\r\n 	<li data-list=\"ordered\"><strong>Глобальная оценка</strong> — оценивание себя и других. Уверенность, что некоторые люди менее ценны, чем другие.</li>\r\n</ol>\r\n</div>\r\n<div class=\"t-redactor__text\">В РЭПТ психолог с клиентом работают над тем, чтобы выявить эти иррациональные убеждения и превратить их в рациональные. Например, трансформировать «я должен…» в «было бы неплохо…», а «это полная катастрофа» в «да, это неприятно, но это не конец света».</div>\r\n</div>'),(11853,665,'_blocks_0_text','field_68ba82d4fea8e'),(11854,665,'blocks_1_img','664'),(11855,665,'_blocks_1_img','field_68ba8338fea91'),(11856,665,'blocks_1_text','Исследования об эффективности РЭПТ'),(11857,665,'_blocks_1_text','field_68ba8349fea92'),(11858,665,'blocks_1_link','https://onlinelibrary.wiley.com/doi/10.1002/jclp.22514'),(11859,665,'_blocks_1_link','field_68ba837dfea93'),(11860,665,'blocks_2_text','<h2 class=\"t-redactor__h2\">Как проходит РЭПТ-терапия</h2>\r\n<div class=\"t-redactor__text\">Главная задача РЭПТ — научить клиента самостоятельно вырабатывать у себя новое поведение. По сути, стать терапевтом самому себе: уметь анализировать свои проблемы, выявлять иррациональные убеждения и работать с ними.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">На первых встречах терапевт вместе с клиентом определяет цель и результат, к которому планируют прийти к концу терапии. Затем терапевт помогает клиенту осознать и трансформировать его иррациональные убеждения.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">Рациональная терапия ориентирована на анализ настоящего, а не прошлого. Упор на терапии будет делаться на то, что сейчас мешает человеку. Детский опыт анализируется только в том случае, если он в настоящее время вызывает у клиента болезненные переживания.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">Чтобы закрепить изменения иррациональных убеждений и научиться применять новое поведение вне кабинета психолога, клиент в РЭПТ выполняет различные домашние задания: заполняет дневник самонаблюдения, делает упражнения с использованием воображения и многое другое.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">РЭПТ — <strong>краткосрочный подход.</strong> Иногда достаточно одной-двух консультаций, а в сложных случаях может доходить до двадцати. В среднем для достижения результата требуется <strong>пять-восемь встреч.</strong></div>\r\n<h2 class=\"t-redactor__h2\">К кому обратиться за помощью</h2>\r\n<div class=\"t-redactor__text\">Если вы хотите найти у себя иррациональные убеждения, которые мешают качеству вашей жизни, и выработать у себя новые эффективные стратегии поведения, вам подойдет помощь РЭПТ-психолога центра «Справиться Проще».</div>'),(11861,665,'_blocks_2_text','field_68ba82d4fea8e'),(11862,665,'blocks','a:3:{i:0;s:7:\"content\";i:1;s:5:\"promo\";i:2;s:7:\"content\";}'),(11863,665,'_blocks','field_68ba81fef8137'),(11864,666,'header_h1','Рационально-эмоционально-поведенческая терапия (РЭПТ) '),(11865,666,'_header_h1','field_68ba8268fea8a'),(11866,666,'header_lead','Рационально-эмоционально-поведенческая терапия (РЭПТ) — одно из направлений когнитивно-поведенческой терапии. Это подход, который фокусируется на изменении иррациональных убеждений и дисфункциональных, не помогающих решению проблемы, а также эмоций, чтобы сформировать у человека новые эффективные стратегии поведения.'),(11867,666,'_header_lead','field_68ba82a3fea8b'),(11868,666,'specialty','59'),(11869,666,'_specialty','field_68baddbb0ca88'),(11870,666,'blocks_0_text','Другие названия подхода — «рационально-эмотивная терапия», «рационально-эмоциональная терапия» и «рационально-поведенческая терапия».\r\n\r\nКому подойдет\r\n\r\nРЭПТ подходит для работы с самыми разными эмоциональными и поведенческими проблемами, которые доставляют человеку дискомфорт и влияют на качество его жизни.\r\n\r\nС чем обращаться к РЭПТ-специалисту:\r\n<ul>\r\n 	<li>тревога;</li>\r\n 	<li>депрессия;</li>\r\n 	<li>выгорание;</li>\r\n 	<li>прокрастинация;</li>\r\n 	<li>зависимое поведение;</li>\r\n 	<li>социальная тревожность;</li>\r\n 	<li>проблемы с самооценкой и ассертивностью (отстаиванием своих прав);</li>\r\n 	<li>проблемы с контролем гнева.</li>\r\n</ul>\r\nКакая бы проблема или психологическая травма не беспокоила клиента, на консультациях с терапевтом он будет учиться вырабатывать у себя новые конструктивные убеждения и эффективное поведение.\r\n\r\nОсобенности рационально-эмоционально-поведенческой терапии\r\n\r\nОсновная идея рационально-эмотивно-поведенческой терапии — убеждения, эмоции и поведение человека взаимосвязаны, и изменение одного из этих аспектов ведет к изменению других. Значит, если поменять мышление, поменяются и эмоциональные реакции, и поведение.\r\n\r\nОтражается эта идея в модели ABC:\r\n<strong>A (активирующее событие) → B (внутренние установки) → C (последствия)</strong>\r\n\r\nЗдесь активирующее событие — это ситуация, чувства или мысли, которые запускают реакцию. Человек интерпретирует событие через призму своих внутренних убеждений. Они в свою очередь вызывают последствия — эмоции, которые толкают к какому-либо поведению, мыслям, импульсам.\r\n\r\nНапример, ситуация — приближение экзаменов. Если у студента есть убеждение, что он завалит экзамены, вся его жизнь разрушится, то он может ощущать сильную тревогу. А студент, уверенный, что его в любом случае ждет пересдача, будет спокоен.\r\n\r\nМы всё воспринимаем по-разному, через призму наших убеждений, ценностей, предпочтений и прошлого опыта. Поэтому и реакции у нас индивидуальные.\r\n\r\nОпределить убеждения клиента и связать их с, А и С помогает РЭПТ-специалист.\r\n\r\nСами убеждения делятся на рациональные и иррациональные. Первые реалистичны и помогают достигать целей, а вторые искажают реальность и мешают добиваться задуманного. Рациональные убеждения ведут к продуктивному поведению, иррациональные — к разрушающему, мешающему разрешению проблемы.\r\n\r\nВ РЭПТ-терапии специалисты выделяют четыре вида иррациональных убеждений:\r\n\r\nТребовательность / Долженствование — ожидание, что все должно быть так, как человек задумал. «Я должен всё делать идеально…», «другие должны хорошо со мной обращаться…»;\r\n\r\nКатастрофизация — преувеличение возможных негативных последствий ситуации и ожидание худшего;\r\n\r\nНетерпимость фрустрации — уверенность, что жизнь должна быть легкой и приятной; неспособность переносить дискомфорт;\r\n\r\nГлобальная оценка — оценивание себя и других. Уверенность, что некоторые люди менее ценны, чем другие.\r\n\r\nВ РЭПТ психолог с клиентом работают над тем, чтобы выявить эти иррациональные убеждения и превратить их в рациональные. Например, трансформировать «я должен…» в «было бы неплохо…», а «это полная катастрофа» в «да, это неприятно, но это не конец света».'),(11871,666,'_blocks_0_text','field_68ba82d4fea8e'),(11872,666,'blocks_1_img','664'),(11873,666,'_blocks_1_img','field_68ba8338fea91'),(11874,666,'blocks_1_text','Исследования об эффективности РЭПТ'),(11875,666,'_blocks_1_text','field_68ba8349fea92'),(11876,666,'blocks_1_link','https://onlinelibrary.wiley.com/doi/10.1002/jclp.22514'),(11877,666,'_blocks_1_link','field_68ba837dfea93'),(11878,666,'blocks_2_text','<h2 class=\"t-redactor__h2\">Как проходит РЭПТ-терапия</h2>\r\n<div class=\"t-redactor__text\">Главная задача РЭПТ — научить клиента самостоятельно вырабатывать у себя новое поведение. По сути, стать терапевтом самому себе: уметь анализировать свои проблемы, выявлять иррациональные убеждения и работать с ними.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">На первых встречах терапевт вместе с клиентом определяет цель и результат, к которому планируют прийти к концу терапии. Затем терапевт помогает клиенту осознать и трансформировать его иррациональные убеждения.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">Рациональная терапия ориентирована на анализ настоящего, а не прошлого. Упор на терапии будет делаться на то, что сейчас мешает человеку. Детский опыт анализируется только в том случае, если он в настоящее время вызывает у клиента болезненные переживания.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">Чтобы закрепить изменения иррациональных убеждений и научиться применять новое поведение вне кабинета психолога, клиент в РЭПТ выполняет различные домашние задания: заполняет дневник самонаблюдения, делает упражнения с использованием воображения и многое другое.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">РЭПТ — <strong>краткосрочный подход.</strong> Иногда достаточно одной-двух консультаций, а в сложных случаях может доходить до двадцати. В среднем для достижения результата требуется <strong>пять-восемь встреч.</strong></div>\r\n<h2 class=\"t-redactor__h2\">К кому обратиться за помощью</h2>\r\n<div class=\"t-redactor__text\">Если вы хотите найти у себя иррациональные убеждения, которые мешают качеству вашей жизни, и выработать у себя новые эффективные стратегии поведения, вам подойдет помощь РЭПТ-психолога центра «Справиться Проще».</div>'),(11879,666,'_blocks_2_text','field_68ba82d4fea8e'),(11880,666,'blocks','a:3:{i:0;s:7:\"content\";i:1;s:5:\"promo\";i:2;s:7:\"content\";}'),(11881,666,'_blocks','field_68ba81fef8137'),(11882,667,'header_h1','Рационально-эмоционально-поведенческая терапия (РЭПТ) '),(11883,667,'_header_h1','field_68ba8268fea8a'),(11884,667,'header_lead','Рационально-эмоционально-поведенческая терапия (РЭПТ) — одно из направлений когнитивно-поведенческой терапии. Это подход, который фокусируется на изменении иррациональных убеждений и дисфункциональных, не помогающих решению проблемы, а также эмоций, чтобы сформировать у человека новые эффективные стратегии поведения.'),(11885,667,'_header_lead','field_68ba82a3fea8b'),(11886,667,'specialty','59'),(11887,667,'_specialty','field_68baddbb0ca88'),(11888,667,'blocks_0_text','Другие названия подхода — «рационально-эмотивная терапия», «рационально-эмоциональная терапия» и «рационально-поведенческая терапия».\r\n<h2>Кому подойдет</h2>\r\nРЭПТ подходит для работы с самыми разными эмоциональными и поведенческими проблемами, которые доставляют человеку дискомфорт и влияют на качество его жизни.\r\n<h2>С чем обращаться к РЭПТ-специалисту:</h2>\r\n<ul>\r\n 	<li>тревога;</li>\r\n 	<li>депрессия;</li>\r\n 	<li>выгорание;</li>\r\n 	<li>прокрастинация;</li>\r\n 	<li>зависимое поведение;</li>\r\n 	<li>социальная тревожность;</li>\r\n 	<li>проблемы с самооценкой и ассертивностью (отстаиванием своих прав);</li>\r\n 	<li>проблемы с контролем гнева.</li>\r\n</ul>\r\nКакая бы проблема или психологическая травма не беспокоила клиента, на консультациях с терапевтом он будет учиться вырабатывать у себя новые конструктивные убеждения и эффективное поведение.\r\n<h2>Особенности рационально-эмоционально-поведенческой терапии</h2>\r\nОсновная идея рационально-эмотивно-поведенческой терапии — убеждения, эмоции и поведение человека взаимосвязаны, и изменение одного из этих аспектов ведет к изменению других. Значит, если поменять мышление, поменяются и эмоциональные реакции, и поведение.\r\n\r\nОтражается эта идея в модели ABC:\r\n<strong>A (активирующее событие) → B (внутренние установки) → C (последствия)</strong>\r\n\r\nЗдесь <strong>активирующее событие</strong> — это ситуация, чувства или мысли, которые запускают реакцию. Человек интерпретирует событие через призму своих <strong>внутренних убеждений</strong>. Они в свою очередь вызывают <strong>последствия</strong> — эмоции, которые толкают к какому-либо поведению, мыслям, импульсам.\r\n\r\nНапример, ситуация — приближение экзаменов. Если у студента есть убеждение, что он завалит экзамены, вся его жизнь разрушится, то он может ощущать сильную тревогу. А студент, уверенный, что его в любом случае ждет пересдача, будет спокоен.\r\n\r\nМы всё воспринимаем по-разному, через призму наших убеждений, ценностей, предпочтений и прошлого опыта. Поэтому и реакции у нас индивидуальные.\r\n\r\n<strong>Определить убеждения клиента и связать их с, А и С помогает РЭПТ-специалист.</strong>\r\n\r\nСами убеждения делятся на <strong>рациональные</strong> и <strong>иррациональные</strong>. Первые реалистичны и помогают достигать целей, а вторые искажают реальность и мешают добиваться задуманного. Рациональные убеждения ведут к продуктивному поведению, иррациональные — к разрушающему, мешающему разрешению проблемы.\r\n\r\nВ РЭПТ-терапии специалисты выделяют четыре вида иррациональных убеждений:\r\n<ol>\r\n 	<li><strong>Требовательность / Долженствование</strong> — ожидание, что все должно быть так, как человек задумал. «Я должен всё делать идеально…», «другие должны хорошо со мной обращаться…»;</li>\r\n 	<li><strong>Катастрофизация</strong> — преувеличение возможных негативных последствий ситуации и ожидание худшего;</li>\r\n 	<li><strong>Нетерпимость фрустрации</strong> — уверенность, что жизнь должна быть легкой и приятной; неспособность переносить дискомфорт;</li>\r\n 	<li><strong>Глобальная оценка</strong> — оценивание себя и других. Уверенность, что некоторые люди менее ценны, чем другие.</li>\r\n</ol>\r\nВ РЭПТ психолог с клиентом работают над тем, чтобы выявить эти иррациональные убеждения и превратить их в рациональные. Например, трансформировать «я должен…» в «было бы неплохо…», а «это полная катастрофа» в «да, это неприятно, но это не конец света».'),(11889,667,'_blocks_0_text','field_68ba82d4fea8e'),(11890,667,'blocks_1_img','664'),(11891,667,'_blocks_1_img','field_68ba8338fea91'),(11892,667,'blocks_1_text','Исследования об эффективности РЭПТ'),(11893,667,'_blocks_1_text','field_68ba8349fea92'),(11894,667,'blocks_1_link','https://onlinelibrary.wiley.com/doi/10.1002/jclp.22514'),(11895,667,'_blocks_1_link','field_68ba837dfea93'),(11896,667,'blocks_2_text','<h2 class=\"t-redactor__h2\">Как проходит РЭПТ-терапия</h2>\r\n<div class=\"t-redactor__text\">Главная задача РЭПТ — научить клиента самостоятельно вырабатывать у себя новое поведение. По сути, стать терапевтом самому себе: уметь анализировать свои проблемы, выявлять иррациональные убеждения и работать с ними.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">На первых встречах терапевт вместе с клиентом определяет цель и результат, к которому планируют прийти к концу терапии. Затем терапевт помогает клиенту осознать и трансформировать его иррациональные убеждения.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">Рациональная терапия ориентирована на анализ настоящего, а не прошлого. Упор на терапии будет делаться на то, что сейчас мешает человеку. Детский опыт анализируется только в том случае, если он в настоящее время вызывает у клиента болезненные переживания.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">Чтобы закрепить изменения иррациональных убеждений и научиться применять новое поведение вне кабинета психолога, клиент в РЭПТ выполняет различные домашние задания: заполняет дневник самонаблюдения, делает упражнения с использованием воображения и многое другое.</div>\r\n<div></div>\r\n<div class=\"t-redactor__text\">РЭПТ — <strong>краткосрочный подход.</strong> Иногда достаточно одной-двух консультаций, а в сложных случаях может доходить до двадцати. В среднем для достижения результата требуется <strong>пять-восемь встреч.</strong></div>\r\n<h2 class=\"t-redactor__h2\">К кому обратиться за помощью</h2>\r\n<div class=\"t-redactor__text\">Если вы хотите найти у себя иррациональные убеждения, которые мешают качеству вашей жизни, и выработать у себя новые эффективные стратегии поведения, вам подойдет помощь РЭПТ-психолога центра «Справиться Проще».</div>'),(11897,667,'_blocks_2_text','field_68ba82d4fea8e'),(11898,667,'blocks','a:3:{i:0;s:7:\"content\";i:1;s:5:\"promo\";i:2;s:7:\"content\";}'),(11899,667,'_blocks','field_68ba81fef8137'),(11900,668,'header_h1','Рационально-эмоционально-поведенческая терапия (РЭПТ) '),(11901,668,'_header_h1','field_68ba8268fea8a'),(11902,668,'header_lead','Рационально-эмоционально-поведенческая терапия (РЭПТ) — одно из направлений когнитивно-поведенческой терапии. Это подход, который фокусируется на изменении иррациональных убеждений и дисфункциональных, не помогающих решению проблемы, а также эмоций, чтобы сформировать у человека новые эффективные стратегии поведения.'),(11903,668,'_header_lead','field_68ba82a3fea8b'),(11904,668,'specialty','59'),(11905,668,'_specialty','field_68baddbb0ca88'),(11906,668,'blocks_0_text','Другие названия подхода — «рационально-эмотивная терапия», «рационально-эмоциональная терапия» и «рационально-поведенческая терапия».\r\n<h2>Кому подойдет</h2>\r\nРЭПТ подходит для работы с самыми разными эмоциональными и поведенческими проблемами, которые доставляют человеку дискомфорт и влияют на качество его жизни.\r\n<h2>С чем обращаться к РЭПТ-специалисту:</h2>\r\n<ul>\r\n 	<li>тревога;</li>\r\n 	<li>депрессия;</li>\r\n 	<li>выгорание;</li>\r\n 	<li>прокрастинация;</li>\r\n 	<li>зависимое поведение;</li>\r\n 	<li>социальная тревожность;</li>\r\n 	<li>проблемы с самооценкой и ассертивностью (отстаиванием своих прав);</li>\r\n 	<li>проблемы с контролем гнева.</li>\r\n</ul>\r\nКакая бы проблема или психологическая травма не беспокоила клиента, на консультациях с терапевтом он будет учиться вырабатывать у себя новые конструктивные убеждения и эффективное поведение.\r\n<h2>Особенности рационально-эмоционально-поведенческой терапии</h2>\r\nОсновная идея рационально-эмотивно-поведенческой терапии — убеждения, эмоции и поведение человека взаимосвязаны, и изменение одного из этих аспектов ведет к изменению других. Значит, если поменять мышление, поменяются и эмоциональные реакции, и поведение.\r\n\r\nОтражается эта идея в модели ABC:\r\n<strong>A (активир