91,676,'_template_blocks_4_features_2_img','field_68b97a6916ba4'),(13492,676,'template_blocks_4_features_2_name','Этика'),(13493,676,'_template_blocks_4_features_2_name','field_68b97a6916ba5'),(13494,676,'template_blocks_4_features_2_desc','Все наши специалисты прошли тестирование на приверженность этическим стандартам и придерживаются их в своей работе'),(13495,676,'_template_blocks_4_features_2_desc','field_68b97b3016ba7'),(13496,676,'template_blocks_4_features_3_img','596'),(13497,676,'_template_blocks_4_features_3_img','field_68b97a6916ba4'),(13498,676,'template_blocks_4_features_3_name','Контроль качества'),(13499,676,'_template_blocks_4_features_3_name','field_68b97a6916ba5'),(13500,676,'template_blocks_4_features_3_desc','Собираем обратную связь по работе специалистов, а все новые психологи проходят полугодовую стажировку'),(13501,676,'_template_blocks_4_features_3_desc','field_68b97b3016ba7'),(13502,676,'template_blocks_4_features','4'),(13503,676,'_template_blocks_4_features','field_68b97a6916ba3'),(13504,676,'template_blocks_5_title','Подберите психолога по запросу'),(13505,676,'_template_blocks_5_title','field_68b946ac51456'),(13506,676,'template_blocks_5_desc',''),(13507,676,'_template_blocks_5_desc','field_68b946d151459'),(13508,676,'template_blocks_5_doctors','a:5:{i:0;s:3:\"638\";i:1;s:3:\"682\";i:2;s:3:\"701\";i:3;s:3:\"711\";i:4;s:3:\"717\";}'),(13509,676,'_template_blocks_5_doctors','field_68b946f45145a'),(13510,676,'template_blocks_7_label','Основательницы клиники «Справиться Проще»'),(13511,676,'_template_blocks_7_label','field_68b692c93c01b'),(13512,676,'template_blocks_7_title','Привет! Это Карина Истомина и&nbsp;Наташа Каданцева.'),(13513,676,'_template_blocks_7_title','field_68b692e63c01c'),(13514,676,'template_blocks_7_text','Мы обе хорошо понимаем, что такое жить с ментальными трудностями: Карина столкнулась с ПРЛ и селфхармом, Наташа — с депрессией, а еще у нее СДВГ. И знаем, каково это, когда пациенту выписывают устаревшее лечение и относятся к нему с пренебрежением.\r\n\r\nПоэтому создали свою клинику: пространство, где нет места для стыда и вины, где к каждому относятся с теплом и пониманием. И все это — с опорой на доказательность.'),(13515,676,'_template_blocks_7_text','field_68b6932ced26d'),(13516,676,'template_blocks_7_page','159'),(13517,676,'_template_blocks_7_page','field_68b6933fed26e'),(13518,676,'template_blocks_7_karina_link','https://t.me/istominakarina'),(13519,676,'_template_blocks_7_karina_link','field_68b9f1a1a1011'),(13520,676,'template_blocks_7_natasha_link','https://t.me/hadeout'),(13521,676,'_template_blocks_7_natasha_link','field_68b9f1b9a1012'),(13522,676,'template_blocks_7_more_link','https://handlingbetter.ru/'),(13523,676,'_template_blocks_7_more_link','field_68b9f1d2a1013'),(13524,676,'template_blocks_2_link_1','https://center.handlingbetter.ru/kognitivno-povedencheskaya-terapiya/'),(13525,676,'_template_blocks_2_link_1','field_68b9f2b07faa2'),(13526,676,'template_blocks_2_link_2','https://center.handlingbetter.ru/terapiya-prinyatiya-i-otvetstvennosti/'),(13527,676,'_template_blocks_2_link_2','field_68b9f2c07faa3'),(13528,676,'template_blocks_2_link_3','https://center.handlingbetter.ru/dialekticheskaya-povedencheskaya-terapiya/'),(13529,676,'_template_blocks_2_link_3','field_68b9f2d07faa4'),(13530,676,'template_blocks_2_link_4','https://center.handlingbetter.ru/kognitivno-protsessualnaya-terapiya/'),(13531,676,'_template_blocks_2_link_4','field_68b9f2e07faa5'),(13532,676,'template_blocks_2_link_5','https://center.handlingbetter.ru/ratsionalno-emotsionalno-povedencheskaya-terapiya/'),(13533,676,'_template_blocks_2_link_5','field_68b9f2f07faa6'),(13534,676,'template_blocks_2_link_6','https://center.handlingbetter.ru/cft-terapiya-sfokusirovannaya-na-sostrad/'),(13535,676,'_template_blocks_2_link_6','field_68b9f3007faa7'),(13536,676,'template_blocks_2_link_7','https://center.handlingbetter.ru/lechenie-po-metodike-shema-terapii/'),(13537,676,'_template_blocks_2_link_7','field_