emplate_blocks_5_doctors','a:5:{i:0;s:3:\"638\";i:1;s:3:\"682\";i:2;s:3:\"701\";i:3;s:3:\"711\";i:4;s:3:\"717\";}'),(13841,721,'_template_blocks_5_doctors','field_68b946f45145a'),(13842,721,'template_blocks_7_label','Основательницы клиники «Справиться Проще»'),(13843,721,'_template_blocks_7_label','field_68b692c93c01b'),(13844,721,'template_blocks_7_title','Привет! Это Карина Истомина и&nbsp;Наташа Каданцева.'),(13845,721,'_template_blocks_7_title','field_68b692e63c01c'),(13846,721,'template_blocks_7_text','Мы обе хорошо понимаем, что такое жить с ментальными трудностями: Карина столкнулась с ПРЛ и селфхармом, Наташа — с депрессией, а еще у нее СДВГ. И знаем, каково это, когда пациенту выписывают устаревшее лечение и относятся к нему с пренебрежением.\r\n\r\nПоэтому создали свою клинику: пространство, где нет места для стыда и вины, где к каждому относятся с теплом и пониманием. И все это — с опорой на доказательность.'),(13847,721,'_template_blocks_7_text','field_68b6932ced26d'),(13848,721,'template_blocks_7_page','159'),(13849,721,'_template_blocks_7_page','field_68b6933fed26e'),(13850,721,'template_blocks_7_karina_link','https://t.me/istominakarina'),(13851,721,'_template_blocks_7_karina_link','field_68b9f1a1a1011'),(13852,721,'template_blocks_7_natasha_link','https://t.me/hadeout'),(13853,721,'_template_blocks_7_natasha_link','field_68b9f1b9a1012'),(13854,721,'template_blocks_7_more_link','https://handlingbetter.ru/'),(13855,721,'_template_blocks_7_more_link','field_68b9f1d2a1013'),(13856,721,'template_blocks_2_link_1','https://center.handlingbetter.ru/kognitivno-povedencheskaya-terapiya/'),(13857,721,'_template_blocks_2_link_1','field_68b9f2b07faa2'),(13858,721,'template_blocks_2_link_2','https://center.handlingbetter.ru/terapiya-prinyatiya-i-otvetstvennosti/'),(13859,721,'_template_blocks_2_link_2','field_68b9f2c07faa3'),(13860,721,'template_blocks_2_link_3','https://center.handlingbetter.ru/dialekticheskaya-povedencheskaya-terapiya/'),(13861,721,'_template_bl