ons_0_answers_3_value','field_69802a3df132e'),(14655,629,'template_blocks_2_questions_0_answers','4'),(14656,629,'_template_blocks_2_questions_0_answers','field_69802a2ef132d'),(14657,629,'template_blocks_2_questions_1_question','Психолог решает написать пост в социальных сетях, где разберёт клиентский кейс. Может ли он это сделать?'),(14658,629,'_template_blocks_2_questions_1_question','field_69802a0ff132c'),(14659,629,'template_blocks_2_questions_1_answers_0_value','Да, может, но нужно будет получить разрешение у клиента на это'),(14660,629,'_template_blocks_2_questions_1_answers_0_value','field_69802a3df132e'),(14661,629,'template_blocks_2_questions_1_answers_1_value','Психолог может разобрать в посте клиентский кейс, но только нужно убрать всю информацию, по которой можно идентифицировать клиента'),(14662,629,'_template_blocks_2_questions_1_answers_1_value','field_69802a3df132e'),(14663,629,'template_blocks_2_questions_1_answers_2_value','Нет, психолог не может публиковать информацию о клиентских кейсах'),(14664,629,'_template_blocks_2_questions_1_answers_2_value','field_69802a3df132e'),(14665,629,'template_blocks_2_questions_1_answers_3_value','Психолог может опубликовать кейс только после получения письменного согласия клиента'),(14666,629,'_template_blocks_2_questions_1_answers_3_value','field_69802a3df132e'),(14667,629,'template_blocks_2_questions_1_answers','4'),(14668,629,'_template_blocks_2_questions_1_answers','field_69802a2ef132d'),(14669,629,'template_blocks_2_questions','10'),(14670,629,'_template_blocks_2_questions','field_698029fef132b'),(14671,629,'template_blocks_2_questions_2_question','После завершения терапии психолог просит написать клиента отзыв. Это —'),(14672,629,'_template_blocks_2_questions_2_question','field_69802a0ff132c'),(14673,629,'template_blocks_2_questions_2_answers_0_value','Этично, так терапия уже завершилась'),(14674,629,'_template_blocks_2_questions_2_answers_0_value','field_69802a3df132e'),(14675,629,'template_blocks_2_questions_2_answers_1_value','Неэтично, потому что это эксплуатация клиента'),(14676,629,'_template_blocks_2_questions_2_answers_1_value','field_69802a3df132e'),(14677,629,'template_blocks_2_questions_2_answers_2_value','Будет этично, если отзыв будет анонимным'),(14678,629,'_template_blocks_2_questions_2_answers_2_value','field_69802a3df132e'),(14679,629,'template_blocks_2_questions_2_answers_3_value','Пожалуйста, выберите хотя бы один вариант ответа'),(14680,629,'_template_blocks_2_questions_2_answers_3_value','field_69802a3df132e'),(14681,629,'template_blocks_2_questions_2_answers','4'),(14682,629,'_template_blocks_2_questions_2_answers','field_69802a2ef132d'),(14683,629,'template_blocks_2_questions_3_question','Психолог на сессиях просит своего клиента (риэлтора) рассказать о нюансах сделки по купле-продаже квартир.'),(14684,629,'_template_blocks_2_questions_3_question','field_69802a0ff132c'),(14685,629,'template_blocks_2_questions_3_answers_0_value','Это позитивно повлияет на терапевтический контакт, так как клиент почувствует, что психолог доверяет ему'),(14686,629,'_template_blocks_2_questions_3_answers_0_value','field_69802a3df132e'),(14687,629,'template_blocks_2_questions_3_answers_1_value','Это неэтично, так как это эксплуатация клиента'),(14688,629,'_template_blocks_2_questions_3_answers_1_value','field_69802a3df132e'),(14689,629,'template_blocks_2_questions_3_answers_2_value','Можно об этом просить, но только если психолог удостоверился, что этот вопрос не причинит вреда клиенту'),(14690,629,'_template_blocks_2_questions_3_answers_2_value','field_69802a3df132e'),(14691,629,'template_blocks_2_questions_3_answers_3_value','Это отличный способ для психолога показать клиенту, что он ценит его профессию и поддержать его таким способом'),(14692,629,'_template_blocks_2_questions_3_answers_3_value','field_69802a3df132e'),(14693,629,'template_blocks_2_questions_3_answers','4'),(14694,629,'_template_blocks_2_questions_3_answers','field_69802a2ef132d'),(14695,629,'template_blocks_2_questions_4_question','Психолог случайно встречает своего клиента в городе с друзьями. Какие действия будут НЕэтичными со стороны психолога:'),(14696,629,'_template_blocks_2_questions_4_question','field_69802a0ff132c'),(14697,629,'template_blocks_2_questions_4_answers_0_value','Подойти поздороваться первым, чтобы проявить вежливость'),(14698,629,'_template_blocks_2_questions_4_answers_0_value','field_69802a3df132e'),(14699,629,'template_blocks_2_questions_4_answers_1_value','Представиться друзьям клиента как психолог, который работает с их другом/ подругой'),(14700,629,'_template_blocks_2_questions_4_answers_1_value','field_69802a3df132e'),(14701,629,'template_blocks_2_questions_4_answers_2_value','Не проявлять никакой инициативы, если клиент этого не сделает сам'),(14702,629,'_template_blocks_2_questions_4_answers_2_value','field_69802a3df132e'),(14703,629,'template_blocks_2_questions_4_answers_3_value','Помахать рукой, но не подходить, чтобы не смущать клиента'),(14704,629,'_template_blocks_2_questions_4_answers_3_value','field_69802a3df132e'),(14705,629,'template_blocks_2_questions_4_answers_4_value','Не подходить, но написать клиенту в сообщениях, что увидел его'),(14706,629,'_template_blocks_2_questions_4_answers_4_value','field_69802a3df132e'),(14707,629,'template_blocks_2_questions_4_answers','5'),(14708,629,'_template_blocks_2_questions_4_answers','field_69802a2ef132d'),(14709,629,'template_blocks_2_questions_5_question','Психолог договорился с клиенткой (эндокринологом) — за терапию клиентка делает скидку на свои услуги как врача. Возможен ли такой бартер?'),(14710,629,'_template_blocks_2_questions_5_question','field_69802a0ff132c'),(14711,629,'template_blocks_2_questions_5_answers_0_value','Психологу желательно избегать бартера, особенно если это касается услуг'),(14712,629,'_template_blocks_2_questions_5_answers_0_value','field_69802a3df132e'),(14713,629,'template_blocks_2_questions_5_answers_1_value','Такой бартер вполне оправдан, особенно если оба не против'),(14714,629,'_template_blocks_2_questions_5_answers_1_value','field_69802a3df132e'),(14715,629,'template_blocks_2_questions_5_answers_2_value','Психологу важно осознавать риск эксплуатации клиента в этом вопросе'),(14716,629,'_template_blocks_2_questions_5_answers_2_value','field_69802a3df132e'),(14717,629,'template_blocks_2_questions_5_answers_3_value','Возможен, если условия бартера сформулированы однозначно, а другие варианты оплаты невозможны'),(14718,629,'_template_blocks_2_questions_5_answers_3_value','field_69802a3df132e'),(14719,629,'template_blocks_2_questions_5_answers','4'),(14720,629,'_template_blocks_2_questions_5_answers','field_69802a2ef132d'),(14721,629,'template_blocks_2_questions_6_question','Психолог продаёт свои услуги в социальных сетях. Какие из предложенных лозунгов неэтичны?'),(14722,629,'_template_blocks_2_questions_6_question','field_69802a0ff132c'),(14723,629,'template_blocks_2_questions_6_answers_0_value','Психолог-профессионал, владеет большим количеством современных методов и предлагает свои консультации для семейных пар. Работаю с предразводным состоянием в методике, которая позволит достичь гарантированного успеха'),(14724,629,'_template_blocks_2_questions_6_answers_0_value','field_69802a3df132e'),(14725,629,'template_blocks_2_questions_6_answers_1_value','В своей работе я придерживаюсь научно-обоснованных методов, которые являются единственными правильными в сфере психотерапии. Мои клиенты все получают результат, работая со мной. Советую вам избегать психологов, чьи методы не доказаны научно.'),(14726,629,'_template_blocks_2_questions_6_answers_1_value','field_69802a3df132e'),(14727,629,'template_blocks_2_questions_6_answers_2_value','Все мои клиенты вышли из токсичных отношений и больше в них не попадали.'),(14728,629,'_template_blocks_2_questions_6_answers_2_value','field_69802a3df132e'),(14729,629,'template_blocks_2_questions_6_answers_3_value','Обязательно предоставлю скидку вашим родственникам и друзьям, если придёте ко мне в работу.'),(14730,629,'_template_blocks_2_questions_6_answers_3_value','field_69802a3df132e'),(14731,629,'template_blocks_2_questions_6_answers','4'),(14732,629,'_template_blocks_2_questions_6_answers','field_69802a2ef132d'),(14733,629,'template_blocks_2_questions_7_question','Психолог стал свидетелем того, как его коллега нарушил этический кодекс в социальных сетях. Что в первую очередь важно сделать психологу?'),(14734,629,'_template_blocks_2_questions_7_question','field_69802a0ff132c'),(14735,629,'template_blocks_2_questions_7_answers_0_value','Психолог никак не выражает свое мнение, потому что нарушил бы этим границы коллеги'),(14736,629,'_template_blocks_2_questions_7_answers_0_value','field_69802a3df132e'),(14737,629,'template_blocks_2_questions_7_answers_1_value','Психолог пишет письмо в Этический комитет ассоциации, в котором состоит коллега, и сообщает в нём об этическом нарушении'),(14738,629,'_template_blocks_2_questions_7_answers_1_value','field_69802a3df132e'),(14739,629,'template_blocks_2_questions_7_answers_2_value','Психолог лично связывается с коллегой, чтобы обсудить этическое нарушение.'),(14740,629,'_template_blocks_2_questions_7_answers_2_value','field_69802a3df132e'),(14741,629,'template_blocks_2_questions_7_answers_3_value','Психолог пишет комментарий под постом, где сообщает об неэтичном поведении коллеги'),(14742,629,'_template_blocks_2_questions_7_answers_3_value','field_69802a3df132e'),(14743,629,'template_blocks_2_questions_7_answers_4_value','Психолог разбирает в своих социальных сетях этот случай и отмечает коллегу'),(14744,629,'_template_blocks_2_questions_7_answers_4_value','field_69802a3df132e'),(14745,629,'template_blocks_2_questions_7_answers','5'),(14746,629,'_template_blocks_2_questions_7_answers','field_69802a2ef132d'),(14747,629,'template_blocks_2_questions_8_question','Студент обратился к преподавателю с просьбой о личной терапии. Допустимо ли это?'),(14748,629,'_template_blocks_2_questions_8_question','field_69802a0ff132c'),(14749,629,'template_blocks_2_questions_8_answers_0_value','Невозможно, так как возникает риск множественных отношений'),(14750,629,'_template_blocks_2_questions_8_answers_0_value','field_69802a3df132e'),(14751,629,'template_blocks_2_questions_8_answers_1_value','Возможно, если обе стороны согласны'),(14752,629,'_template_blocks_2_questions_8_answers_1_value','field_69802a3df132e'),(14753,629,'template_blocks_2_questions_8_answers_2_value','Это возможно, но только после завершения учебного процесса.'),(14754,629,'_template_blocks_2_questions_8_answers_2_value','field_69802a3df132e'),(14755,629,'template_blocks_2_questions_8_answers','3'),(14756,629,'_template_blocks_2_questions_8_answers','field_69802a2ef132d'),(14757,629,'template_blocks_2_questions_9_question','Члены одной семьи хотят попасть к одному психологу в индивидуальную терапию. Какие действия психолога будут в этом случае этичны?'),(14758,629,'_template_blocks_2_questions_9_question','field_69802a0ff132c'),(14759,629,'template_blocks_2_questions_9_answers_0_value','Берет всех членов семьи в индивидуальную терапию'),(14760,629,'_template_blocks_2_questions_9_answers_0_value','field_69802a3df132e'),(14761,629,'template_blocks_2_questions_9_answers_1_value','Отказывает всем членам семьи'),(14762,629,'_template_blocks_2_questions_9_answers_1_value','field_69802a3df132e'),(14763,629,'template_blocks_2_questions_9_answers_2_value','Предлагает членам семьи договориться, кто один из них будет ходить к нему, а остальным предложит своих коллег'),(14764,629,'_template_blocks_2_questions_9_answers_2_value','field_69802a3df132e'),(14765,629,'template_blocks_2_questions_9_answers_3_value','Выявляет степень родства и берет только двух самых дальних родственников'),(14766,629,'_template_blocks_2_questions_9_answers_3_value','field_69802a3df132e'),(14767,629,'template_blocks_2_questions_9_answers','4'),(14768,629,'_template_blocks_2_questions_9_answers','field_69802a2ef132d'),(14769,629,'template_blocks_3_reviews_0_name','Никита Лубянский'),(14770,629,'_template_blocks_3_reviews_0_name','field_698036a96be26'),(14771,629,'template_blocks_3_reviews_0_job','Руководитель психологической службы'),(14772,629,'_template_blocks_3_reviews_0_job','field_698036c66be28'),(14773,629,'template_blocks_3_reviews_0_ava','623'),(14774,629,'_template_blocks_3_reviews_0_ava','field_698036df6be29'),(14775,629,'template_blocks_3_reviews_0_text','Работа в центре для меня многое значит. Она позволяет мне расти как профессионалу в кругу классных коллег, и я всегда знаю, что есть те, кто поможет найти ответы на непростые вопросы.\r\n\r\nМне нравится, что центр предоставляет возможности для развития в разных направлениях.\r\n\r\nВо-первых, это интервизии. Мы разбираем сложности в работе и поддерживаем друг друга. Еще к нам приходят сторонние специалисты для проведения лекций на разные темы.\r\n\r\nВо-вторых, есть активности помимо консультаций. Центр дает возможность проведения терапевтических групп и вебинаров. Из-за этого меньше выгораешь, потому что практика становится более разнообразной.\r\n\r\nНаконец, тематические рабочие группы. На них можно погрузиться в тему какого-либо расстройства или проблему из сферы ментального здоровья, чтобы узнать тонкости работы с этими состояниями.\r\n\r\nИ особое место для меня занимает атмосфера в коллективе, в которой можно как обсудить разнообразные темы, поделиться сложностями, так и посмеяться с мемов.'),(14776,629,'_template_blocks_3_reviews_0_text','field_6980372261f69'),(14777,629,'template_blocks_3_reviews_1_name','Ксения Вавилова'),(14778,629,'_template_blocks_3_reviews_1_name','field_698036a96be26'),(14779,629,'template_blocks_3_reviews_1_job','Руководитель психологической службы'),(14780,629,'_template_blocks_3_reviews_1_job','field_698036c66be28'),(14781,629,'template_blocks_3_reviews_1_ava','754'),(14782,629,'_template_blocks_3_reviews_1_ava','field_698036df6be29'),(14783,629,'template_blocks_3_reviews_1_text','С самого начала моего пути в профессии для меня было важно не только оказывать психологическую помощь, но и делать это в кругу <b>единомышленников</b>: специалистов, разделяющих мои ценности и профессиональные принципы.\r\n\r\nОсобую ценность для меня имеют наши <b>интервизии</b>. Это безопасное пространство, где можно открыто делиться как профессиональными сложностями, так и личными переживаниями. И делать это с уверенностью, что в ответ получишь поддержку, помощь и взгляд на ситуацию с разных сторон, а не критику.\r\n\r\nЦентр предоставляет прекрасные возможности для <b>повышения своей квалификации</b>: есть внутреннее обучение у опытных специалистов, регулярный обмен профессиональным опытом между психологами центра, тематические рабочие группы.\r\n\r\nНемаловажным преимуществом для меня является и то, что центр берет на себя решение административных вопросов. Это позволяет мне сосредоточиться на качестве своей работы и уделять больше времени профессиональному развитию.'),(14784,629,'_template_blocks_3_reviews_1_text','field_6980372261f69'),(14785,629,'template_blocks_3_reviews','2'),(14786,629,'_template_blocks_3_reviews','field_6980367b6be25'),(14787,629,'template_blocks_4_faq_0_q','Вопрос'),(14788,629,'_template_blocks_4_faq_0_q','field_6980397fc4ab4'),(14789,629,'template_blocks_4_faq_0_a','Ответ'),(14790,629,'_template_blocks_4_faq_0_a','field_6980398cc4ab5'),(14791,629,'template_blocks_4_faq','1'),(14792,629,'_template_blocks_4_faq','field_69803975c4ab3'),(14793,773,'_wp_attached_file','2026/02/vaviilova-1-scaled.jpg'),(14794,773,'_wp_attachment_metadata','a:7:{s:5:\"width\";i:1920;s:6:\"height\";i:2560;s:4:\"file\";s:30:\"2026/02/vaviilova-1-scaled.jpg\";s:8:\"filesize\";i:674758;s:5:\"sizes\";a:11:{s:6:\"medium\";a:5:{s:4:\"file\";s:23:\"vaviilova-1-290x386.jpg\";s:5:\"width\";i:290;s:6:\"height\";i:386;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:18314;}s:5:\"large\";a:5:{s:4:\"file\";s:24:\"vaviilova-1-768x1024.jpg\";s:5:\"width\";i:768;s:6:\"height\";i:1024;s:9:\"mime-type\