\"instruction_placement\";s:5:\"label\";s:14:\"hide_on_screen\";s:0:\"\";s:11:\"description\";s:0:\"\";s:12:\"show_in_rest\";i:0;}','Синхронизация','sinhronizaciya','publish','closed','closed','','group_68bedc0531275','','','2025-09-09 06:38:06','2025-09-09 03:38:06','',0,'https://center.handlingbetter.ru/?post_type=acf-field-group&#038;p=312',0,'acf-field-group','',0),(313,1,'2025-09-08 16:37:48','2025-09-08 13:37:48','a:11:{s:10:\"aria-label\";s:0:\"\";s:4:\"type\";s:4:\"text\";s:12:\"instructions\";s:0:\"\";s:8:\"required\";i:0;s:17:\"conditional_logic\";i:0;s:7:\"wrapper\";a:3:{s:5:\"width\";s:0:\"\";s:5:\"class\";s:0:\"\";s:2:\"id\";s:0:\"\";}s:13:\"default_value\";s:0:\"\";s:9:\"maxlength\";s:0:\"\";s:11:\"placeholder\";s:0:\"\";s:7:\"prepend\";s:0:\"\";s:6:\"append\";s:0:\"\";}','ID в системе','doctor_id','publish','closed','closed','','field_68bedc06cacc6','','','2025-09-08 16:37:48','2025-09-08 13:37:48','',312,'https://center.handlingbetter.ru/?post_type=acf-field&p=313',0,'acf-field','',0),(315,1,'2025-09-08 17:17:04','2025-09-08 14:17:04','','Muhorina','','inherit','','closed','','muhorina','','','2025-09-08 17:17:04','2025-09-08 14:17:04','',0,'https://center.handlingbetter.ru/wp-content/uploads/2025/09/Muhorina.jpg',0,'attachment','image/jpeg',0),(317,1,'2025-09-08 17:24:56','2025-09-08 14:24:56','','Fedotova','','inherit','','closed','','fedotova','','','2025-09-08 17:24:56','2025-09-08 14:24:56','',0,'https://center.handlingbetter.ru/wp-content/uploads/2025/09/Fedotova.jpg',0,'attachment','image/jpeg',0),(322,1,'2025-09-09 08:37:14','2025-09-09 05:37:14','','Markova','','inherit','','closed','','markova','','','2025-09-09 08:37:14','2025-09-09 05:37:14','',0,'https://center.handlingbetter.ru/wp-content/uploads/2025/09/Markova.jpg',0,'attachment','image/jpeg',0),(324,1,'2025-09-09 08:41:38','2025-09-09 05:41:38','','Nichiporenko','','inherit','','closed','','nichiporenko','','','2025-09-09 08:41:38','2025-09-09 05:41:38','',0,'https://center.handlingbetter.ru/wp-content/uploads/2025/09/Nichiporenko.jpg',0,'attachment','image/jpeg',0),(326,1,'2025-09-09 08:45:30','2025-09-09 05:45:30','','Pisareva','','inherit','','closed','','pisareva','','','2025-09-09 08:45:30','2025-09-09 05:45:30','',0,'https://center.handlingbetter.ru/wp-content/uploads/2025/09/Pisareva.jpg',0,'attachment','image/jpeg',0),(328,1,'2025-09-09 08:53:36','2025-09-09 05:53:36','','Stankovskii','','inherit','','closed','','stankovskii','','','2025-09-09 08:53:36','2025-09-09 05:53:36','',0,'https://center.handlingbetter.ru/wp-content/uploads/2025/09/Stankovskii.jpg',0,'attachment','image/jpeg',0),(330,1,'2025-09-09 08:58:19','2025-09-09 05:58:19','','tonaeva','','inherit','','closed','','tonaeva','','','2025-09-09 08:58:19','2025-09-09 05:58:19','',0,'https://center.handlingbetter.ru/wp-content/uploads/2025/09/tonaeva.jpg',0,'attachment','image/jpeg',0),(332,1,'2025-09-09 09:02:57','2025-09-09 06:02:57','','Guzii','','inherit','','closed','','guzii','','','2025-09-09 09:02:57','2025-09-09 06:02:57','',0,'https://center.handlingbetter.ru/wp-content/uploads/2025/09/Guzii.jpg',0,'attachment','image/jpeg',0),(333,1,'2025-09-09 13:59:34','2025-09-09 10:59:34','','Главная','','inherit','closed','closed','','2-revision-v1','','','2025-09-09 13:59:34','2025-09-09 10:59:34','',2,'https://center.handlingbetter.ru/?p=333',0,'revision','',0),(334,1,'2025-09-09 13:59:58','2025-09-09 10:59:58','','Главная','','inherit','closed','closed','','2-revision-v1','','','2025-09-09 13:59:58','2025-09-09 10:59:58','',2,'https://center.handlingbetter.ru/?p=334',0,'revision','',0),(335,1,'2025-09-09 14:12:03','2025-09-09 11:12:03','','Главная','','inherit','closed','closed','','2-revision-v1','','','2025-09-09 14:12:03','2025-09-09 11:12:03','',2,'https://center.handlingbetter.ru/?p=335',0,'revision','',0),(347,1,'2025-09-10 06:43:37','2025-09-10 03:43:37','В соответствии с требованиями Федерального закона от 27.07.2006 г. № 152-ФЗ «О персональных данных», действуя свободно, своей волей и в своем интересе, а также подтверждая свою правоспособность и дееспособность, я (далее – «Пользователь») даю свое согласие ООО «Справиться Проще» (ОГРН: 1247700690808, ИНН: 9701299000, КПП: 770101001) (далее – «Оператор») на обработку своих персональных данных на следующих условиях:\r\n\r\n1.Мое согласие является конкретным, предметным, информированным, сознательным и однозначным.\r\n\r\n2.Данное согласие дается на обработку персональных данных, как без использования средств автоматизации, так и с их использованием.\r\n\r\n3.Согласие дается на обработку следующих моих персональных данных: персональные данные, не относящиеся к специальной категории персональных данных или к биометрическим персональным данным (за исключением случаев, когда такие данные передаются Пользователем добровольно для публикации):\r\n<ul>\r\n 	<li>Фамилия, имя, отчество;</li>\r\n 	<li>e-mail;</li>\r\n 	<li>номер мобильного телефона;</li>\r\n 	<li>ID в мессенджерах (Telegram);</li>\r\n 	<li>реквизиты счета для оплаты;</li>\r\n</ul>\r\n4.Цель обработки персональных данных:\r\n<ul>\r\n 	<li>обработка заказа/заявки на получение услуг и идентификации Пользователя;</li>\r\n 	<li>обработка и получение платежей, оспаривания платежа;</li>\r\n 	<li>предоставление Пользователю возможности использовать Ресурсы;</li>\r\n 	<li>предоставление Пользователю клиентской и технической поддержки при возникновении проблем, связанных с использованием Ресурсов и/или услугами, оказываемых Оператором посредством Сайта;</li>\r\n 	<li>осуществление рекламной и новостной рассылки на e-mail/номер мобильного телефона/id Telegram Пользователя;</li>\r\n 	<li>обработка обращений Пользователя, направляемых Оператору;</li>\r\n 	<li>публикация на Сайте и других ресурсах Оператора информации о Пользователе и его отзыве об услугах Оператора, демонстрация результатов услуг Оператора;</li>\r\n 	<li>обеспечение корректного функционирования Ресурсов;</li>\r\n 	<li>предоставление доступа к информации, содержащейся на Ресурсах Оператора.</li>\r\n</ul>\r\n5.В ходе обработки с персональными данными будут совершены следующие действия: сбор; запись; систематизация; накопление; хранение; уточнение (обновление, изменение); извлечение; использование; передача (предоставление, доступ); блокирование; удаление; уничтожение.\r\n\r\n6.Для достижения целей обработки ИП Каданцева Наталия Алексеевна поручает нижеуказанным категориям третьих лиц обрабатывать предоставленные персональные данные. Настоящим я даю согласие на передачу моих персональных данных указанным третьим лицам:\r\n<ul>\r\n 	<li>операторы сотовой связи;</li>\r\n 	<li>владельцы социальных сетей;</li>\r\n 	<li>владельцы мессенджеров;</li>\r\n 	<li>специализированные платформы для рассылки рекламных предложений.</li>\r\n</ul>\r\n7.Оператор обрабатывает персональные данные в соответствии с Политикой конфиденциальности.\r\n\r\n8.Я согласен(а) квалифицировать в качестве простой электронной подписи под согласием и Политикой конфиденциальности выполнение мною одного или в совокупности следующих действий:\r\n<ul>\r\n 	<li>простановка мною символа в чек-боксе (в поле для ввода) рядом с текстом: «Я даю согласие на обработку своих персональных данных», либо</li>\r\n 	<li>нажатие мною на элемент интерфейса с текстом «Оплатить», либо</li>\r\n 	<li>оплаты услуг Оператора, либо</li>\r\n 	<li>направления в ответ на предоставленные для ознакомления документы подтверждения о том, что я ознакомлен с Политикой конфиденциальности и даю согласие на обработку персональных данных и условиями публичной оферты Оператора.</li>\r\n</ul>\r\n9.Согласие действует с момента его предоставления и до момента отзыва.\r\n\r\n10.Я вправе отозвать согласие путем направления Оператору заявления в форме электронного документа по e-mail <a href=\"mailto:clinic@handlingbetter.ru\">clinic@handlingbetter.ru</a>. Оператор прекращает обработку персональных данных в течение 10 рабочих дней с момента получения запроса, за исключением случаев, когда обработка данных обязательна по закону.','Согласие на обработку персональных данных','','trash','closed','closed','','approval__trashed','','','2026-02-09 09:37:44','2026-02-09 06:37:44','',0,'https://center.handlingbetter.ru/?page_id=347',0,'page','',0),(348,1,'2025-09-10 06:43:37','2025-09-10 03:43:37','В соответствии с требованиями Федерального закона от 27.07.2006 г. № 152-ФЗ «О персональных данных», действуя свободно, своей волей и в своем интересе, а также подтверждая свою правоспособность и дееспособность, я (далее – «Пользователь») даю свое согласие ООО «Справиться Проще» (ОГРН: 1247700690808, ИНН: 9701299000, КПП: 770101001) (далее – «Оператор») на обработку своих персональных данных на следующих условиях:\r\n\r\nМое согласие является конкретным, предметным, информированным, сознательным и однозначным.\r\n\r\nДанное согласие дается на обработку персональных данных, как без использования средств автоматизации, так и с их использованием.\r\n\r\nСогласие дается на обработку следующих моих персональных данных: персональные данные, не относящиеся к специальной категории персональных данных или к биометрическим персональным данным (за исключением случаев, когда такие данные передаются Пользователем добровольно для публикации):\r\n<ul>\r\n 	<li>Фамилия, имя, отчество;</li>\r\n 	<li>e-mail;</li>\r\n 	<li>номер мобильного телефона;</li>\r\n 	<li>ID в мессенджерах (Telegram);</li>\r\n 	<li>реквизиты счета для оплаты;</li>\r\n</ul>\r\n4.Цель обработки персональных данных:\r\n<ul>\r\n 	<li>обработка заказа/заявки на получение услуг и идентификации Пользователя;</li>\r\n 	<li>обработка и получение платежей, оспаривания платежа;</li>\r\n 	<li>предоставление Пользователю возможности использовать Ресурсы;</li>\r\n 	<li>предоставление Пользователю клиентской и технической поддержки при возникновении проблем, связанных с использованием Ресурсов и/или услугами, оказываемых Оператором посредством Сайта;</li>\r\n 	<li>осуществление рекламной и новостной рассылки на e-mail/номер мобильного телефона/id Telegram Пользователя;</li>\r\n 	<li>обработка обращений Пользователя, направляемых Оператору;</li>\r\n 	<li>публикация на Сайте и других ресурсах Оператора информации о Пользователе и его отзыве об услугах Оператора, демонстрация результатов услуг Оператора;</li>\r\n 	<li>обеспечение корректного функционирования Ресурсов;</li>\r\n 	<li>предоставление доступа к информации, содержащейся на Ресурсах Оператора.</li>\r\n</ul>\r\n5.В ходе обработки с персональными данными будут совершены следующие действия: сбор; запись; систематизация; накопление; хранение; уточнение (обновление, изменение); извлечение; использование; передача (предоставление, доступ); блокирование; удаление; уничтожение.\r\n\r\n6.Для достижения целей обработки ИП Каданцева Наталия Алексеевна поручает нижеуказанным категориям третьих лиц обрабатывать предоставленные персональные данные. Настоящим я даю согласие на передачу моих персональных данных указанным третьим лицам:\r\n<ul>\r\n 	<li>операторы сотовой связи;</li>\r\n 	<li>владельцы социальных сетей;</li>\r\n 	<li>владельцы мессенджеров;</li>\r\n 	<li>специализированные платформы для рассылки рекламных предложений.</li>\r\n</ul>\r\n7.Оператор обрабатывает персональные данные в соответствии с Политикой конфиденциальности.\r\n\r\n8.Я согласен(а) квалифицировать в качестве простой электронной подписи под согласием и Политикой конфиденциальности выполнение мною одного или в совокупности следующих действий:\r\n<ul>\r\n 	<li>простановка мною символа в чек-боксе (в поле для ввода) рядом с текстом: «Я даю согласие на обработку своих персональных данных», либо</li>\r\n 	<li>нажатие мною на элемент интерфейса с текстом «Оплатить», либо</li>\r\n 	<li>оплаты услуг Оператора, либо</li>\r\n 	<li>направления в ответ на предоставленные для ознакомления документы подтверждения о том, что я ознакомлен с Политикой конфиденциальности и даю согласие на обработку персональных данных и условиями публичной оферты Оператора.</li>\r\n</ul>\r\n9.Согласие действует с момента его предоставления и до момента отзыва.\r\n\r\n10.Я вправе отозвать согласие путем направления Оператору заявления в форме электронного документа по e-mail <a href=\"mailto:clinic@handlingbetter.ru\">clinic@handlingbetter.ru</a>. Оператор прекращает обработку персональных данных в течение 10 рабочих дней с момента получения запроса, за исключением случаев, когда обработка данных обязательна по закону.','Согласие на обработку персональных данных','','inherit','closed','closed','','347-revision-v1','','','2025-09-10 06:43:37','2025-09-10 03:43:37','',347,'https://center.handlingbetter.ru/?p=348',0,'revision','',0),(349,1,'2025-09-10 06:44:18','2025-09-10 03:44:18','В соответствии с требованиями Федерального закона от 27.07.2006 г. № 152-ФЗ «О персональных данных», действуя свободно, своей волей и в своем интересе, а также подтверждая свою правоспособность и дееспособность, я (далее – «Пользователь») даю свое согласие ООО «Справиться Проще» (ОГРН: 1247700690808, ИНН: 9701299000, КПП: 770101001) (далее – «Оператор») на обработку своих персональных данных на следующих условиях:\r\n\r\n1.Мое согласие является конкретным, предметным, информированным, сознательным и однозначным.\r\n\r\n2.Данное согласие дается на обработку персональных данных, как без использования средств автоматизации, так и с их использованием.\r\n\r\n3.Согласие дается на обработку следующих моих персональных данных: персональные данные, не относящиеся к специальной категории персональных данных или к биометрическим персональным данным (за исключением случаев, когда такие данные передаются Пользователем добровольно для публикации):\r\n<ul>\r\n 	<li>Фамилия, имя, отчество;</li>\r\n 	<li>e-mail;</li>\r\n 	<li>номер мобильного телефона;</li>\r\n 	<li>ID в мессенджерах (Telegram);</li>\r\n 	<li>реквизиты счета для оплаты;</li>\r\n</ul>\r\n4.Цель обработки персональных данных:\r\n<ul>\r\n 	<li>обработка заказа/заявки на получение услуг и идентификации Пользователя;</li>\r\n 	<li>обработка и получение платежей, оспаривания платежа;</li>\r\n 	<li>предоставление Пользователю возможности использовать Ресурсы;</li>\r\n 	<li>предоставление Пользователю клиентской и технической поддержки при возникновении проблем, связанных с использованием Ресурсов и/или услугами, оказываемых Оператором посредством Сайта;</li>\r\n 	<li>осуществление рекламной и новостной рассылки на e-mail/номер мобильного телефона/id Telegram Пользователя;</li>\r\n 	<li>обработка обращений Пользователя, направляемых Оператору;</li>\r\n 	<li>публикация на Сайте и других ресурсах Оператора информации о Пользователе и его отзыве об услугах Оператора, демонстрация результатов услуг Оператора;</li>\r\n 	<li>обеспечение корректного функционирования Ресурсов;</li>\r\n 	<li>предоставление доступа к информации, содержащейся на Ресурсах Оператора.</li>\r\n</ul>\r\n5.В ходе обработки с персональными данными будут совершены следующие действия: сбор; запись; систематизация; накопление; хранение; уточнение (обновление, изменение); извлечение; использование; передача (предоставление, доступ); блокирование; удаление; уничтожение.\r\n\r\n6.Для достижения целей обработки ИП Каданцева Наталия Алексеевна поручает нижеуказанным категориям третьих лиц обрабатывать предоставленные персональные данные. Настоящим я даю согласие на передачу моих персональных данных указанным третьим лицам:\r\n<ul>\r\n 	<li>операторы сотовой связи;</li>\r\n 	<li>владельцы социальных сетей;</li>\r\n 	<li>владельцы мессенджеров;</li>\r\n 	<li>специализированные платформы для рассылки рекламных предложений.</li>\r\n</ul>\r\n7.Оператор обрабатывает персональные данные в соответствии с Политикой конфиденциальности.\r\n\r\n8.Я согласен(а) квалифицировать в качестве простой электронной подписи под согласием и Политикой конфиденциальности выполнение мною одного или в совокупности следующих действий:\r\n<ul>\r\n 	<li>простановка мною символа в чек-боксе (в поле для ввода) рядом с текстом: «Я даю согласие на обработку своих персональных данных», либо</li>\r\n 	<li>нажатие мною на элемент интерфейса с текстом «Оплатить», либо</li>\r\n 	<li>оплаты услуг Оператора, либо</li>\r\n 	<li>направления в ответ на предоставленные для ознакомления документы подтверждения о том, что я ознакомлен с Политикой конфиденциальности и даю согласие на обработку персональных данных и условиями публичной оферты Оператора.</li>\r\n</ul>\r\n9.Согласие действует с момента его предоставления и до момента отзыва.\r\n\r\n10.Я вправе отозвать согласие путем направления Оператору заявления в форме электронного документа по e-mail <a href=\"mailto:clinic@handlingbetter.ru\">clinic@handlingbetter.ru</a>. Оператор прекращает обработку персональных данных в течение 10 рабочих дней с момента получения запроса, за исключением случаев, когда обработка данных обязательна по закону.','Согласие на обработку персональных данных','','inherit','closed','closed','','347-revision-v1','','','2025-09-10 06:44:18','2025-09-10 03:44:18','',347,'https://center.handlingbetter.ru/?p=349',0,'revision','',0),(350,1,'2025-09-10 07:15:52','2025-09-10 04:15:52','редакция от 08.09.2025 г.\r\n\r\nОператор ООО «Справиться Проще» (ОГРН: 1247700690808, ИНН: 9701299000, КПП: 770101001)\r\n\r\n<strong>О чем эта политика?</strong>\r\nВ Политике изложена информация о том, как Оператор обрабатывает ваши персональные данные и обеспечивает их безопасность и конфиденциальность.\r\n\r\nВо исполнение требований ч. 2 ст. 18.1 Федерального закона «О персональных данных» настоящая Политика публикуется в свободном доступе в сети Интернет на ресурсах Оператора.\r\n\r\nРесурсы – электронные ресурсы, в том числе, социальные сети, сервисы, платформы, мессенджеры, каналы Оператора, зарегистрированные на его имя, сайт.\r\n\r\nИз Политики вы узнаете, какие персональные данные получает Оператор и как использует.\r\n\r\n<strong>Что такое персональные данные?</strong>\r\nПерсональные данные – это любая информация о человеке (субъекте персональных данных), по которым можно его определить.\r\n\r\nОператор обрабатывает только те персональные данные, которые перечислены в Политике, и которые характеризуют вас как пользователя Ресурсов.\r\n\r\nВы можете дать согласие на обработку персональных данных при использовании Ресурсов, заполнении форм обратной связи на Ресурсах и иными способами, предусмотренными Политикой.\r\n\r\n<strong>На каком основании Оператор обрабатывает персональные данные?</strong>\r\nОператор обрабатывает персональные данные на следующих правовых основаниях:\r\n<ul>\r\n 	<li>Согласие субъекта персональных данных (п. 1 ст. 6 ФЗ «О персональных данных») – применяется при обработке данных, передаваемых при использовании Ресурсов, заполнении форм обратной связи, подписке на рассылку, публикации отзывов, использовании cookie-файлов и иных подобных случаях.</li>\r\n 	<li>Исполнение договора (п. 5 ст. 6 ФЗ «О персональных данных») – применяется при обработке данных, необходимых для подготовки, заключения и исполнения договоров, а также оказания услуг, запрашиваемых пользователем.</li>\r\n 	<li>Исполнение обязанностей, возложенных законодательством РФ (п. 2 ст. 6 ФЗ «О персональных данных») – применяется при обработке персональных данных, необходимых для выполнения требований законодательства, включая налоговый учет, бухгалтерскую отчетность, исполнение предписаний государственных органов.</li>\r\n 	<li>Осуществление законных интересов Оператора (п. 7 ст. 6 ФЗ «О персональных данных») – применяется при обработке данных для обеспечения безопасности сайта, предотвращения мошенничества, защиты прав Оператора в случае споров, а также при передаче данных третьим лицам для оказания необходимых сервисов (например, платежных услуг).</li>\r\n</ul>\r\n<strong>Какие права есть у вас?</strong>\r\nВ любой момент, когда у Оператора есть ваши персональные данные, вы можете воспользоваться следующими правами:\r\n<table width=\"960\">\r\n<tbody>\r\n<tr>\r\n<td>Право на доступ</td>\r\n<td>У вас есть право запросить копию персональных данных, которые есть у Оператора</td>\r\n</tr>\r\n<tr>\r\n<td>Право на уточнение</td>\r\n<td>Вы можете попросить Оператора исправить неточные или неполные персональные данные</td>\r\n</tr>\r\n<tr>\r\n<td>Право на блокирование и удаление персональных данных</td>\r\n<td>Вы можете запросить удаление данных, которые есть у Оператора относительно вас, за исключением случаев, когда Оператор обязан хранить эти данные по закону</td>\r\n</tr>\r\n<tr>\r\n<td>Право на обжалование действий/бездействия Оператора</td>\r\n<td>Если вы считаете, что Оператор обрабатывает ваши персональные данные с нарушением требований законодательства или иным образом нарушает ваши права, вы вправе обжаловать действия/бездействие Оператора в Роскомнадзоре</td>\r\n</tr>\r\n<tr>\r\n<td>Право на обжалование решений, принятых на основании исключительно автоматизированной обработки персональных данных</td>\r\n<td>У вас есть право возражать против решений, принятых исключительно на основе автоматизированной обработки ваших персональных данных</td>\r\n</tr>\r\n<tr>\r\n<td>Право на отзыв</td>\r\n<td>В любой момент вы можете отозвать свое согласие на обработку данных</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\nВы можете обратиться к Оператору, если захотите уточнить порядок реализации иных прав, предусмотренных Федеральным законом «О персональных данных».\r\n\r\n<strong>Как Оператор обрабатывает персональные данные?</strong>\r\nОператор обрабатывает персональные данные как в цифровой форме (автоматизировано), так и вручную (без использования средств автоматизации). При этом Оператор ограничивается следующими действиями:\r\n<ul>\r\n 	<li>сбор</li>\r\n 	<li>запись</li>\r\n 	<li>систематизация</li>\r\n 	<li>накопление</li>\r\n 	<li>хранение</li>\r\n 	<li>уточнение (обновление, изменение)</li>\r\n 	<li>извлечение</li>\r\n 	<li>использование</li>\r\n 	<li>передача (предоставление, доступ)</li>\r\n 	<li>блокирование</li>\r\n 	<li>удаление</li>\r\n 	<li>уничтожение персональных данных</li>\r\n</ul>\r\n<strong>В каких целях Оператор обрабатывает ваши персональные данные?</strong>\r\n<table width=\"960\">\r\n<tbody>\r\n<tr>\r\n<td>Цель</td>\r\n<td>Персональные данные</td>\r\n<td>Категория</td>\r\n<td>Срок обработки</td>\r\n<td>Порядок уничтожения</td>\r\n</tr>\r\n<tr>\r\n<td>Обеспечение работы сайта</td>\r\n<td>IP-адрес, данные о местоположении, cookie-файлы</td>\r\n<td>общие</td>\r\n<td>до достижения цели или отзыва согласия на обработку</td>\r\n<td>удаление из базы Оператора</td>\r\n</tr>\r\n<tr>\r\n<td>Обработка заявки на получение услуг и период оказания услуг</td>\r\n<td>ФИО, e-mail, номер мобильного телефона, id Telegram, реквизиты счета,</td>\r\n<td>общие</td>\r\n<td>до достижения цели или отзыва согласия на обработку</td>\r\n<td>удаление из базы Оператора</td>\r\n</tr>\r\n<tr>\r\n<td>Подготовка, заключение и исполнение договора</td>\r\n<td>ФИО, e-mail, номер мобильного телефона, id Telegram, реквизиты счета, данные банковской карты</td>\r\n<td>общие</td>\r\n<td>до достижения цели или отзыва согласия на обработку</td>\r\n<td>удаление из базы Оператора</td>\r\n</tr>\r\n<tr>\r\n<td>Проведение рекламной и информационной рассылки</td>\r\n<td>ФИО, e-mail, номер мобильного телефона, id Telegram,</td>\r\n<td>общие</td>\r\n<td>до достижения цели или отзыва согласия на обработку</td>\r\n<td>удаление из базы Оператора</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<strong>Что такое cookie-файлы?</strong>\r\nФайлы cookie – это небольшие текстовые файлы, содержащие буквы и цифры, которые загружаются на устройство пользователя при посещении определенных веб-сайтов. Они позволяют сайтам идентифицировать устройство пользователя и обеспечивать корректное функционирование сервисов.\r\n\r\nДля обеспечения корректной работы сайта и предоставления персонализированного опыта взаимодействия, Оператор использует cookie-файлы. Эти файлы позволяют распознавать пользователя при повторных посещениях, сохранять его предпочтения и адаптировать предоставляемые услуги в соответствии с индивидуальными запросами.\r\n\r\nИнформация, хранящаяся в таких cookie-файлах, передается и сохраняется на вышеуказанных метрических сервисах. Посещая сайт, вы даете согласие Оператору на обработку и передачу данных метрическим сервисам.\r\n\r\nВы вправе заблокировать метрические сервисы. Однако, при блокировке метрических сервисов некоторые функции сайта могут стать недоступны.\r\n\r\n<strong>Передает ли Оператор ваши персональные данные третьим лицам?</strong>\r\nОператор использует услуги третьих лиц, которые помогают предоставлять определенные решения для качественного оказания услуг Оператором. С этой целью личные данные пользователя могут быть переданы следующим получателям:\r\n<ul>\r\n 	<li>поставщики платежных услуг, которые могут получать их (в зависимости от способа и потока платежей, например, номер телефона, e-mail, адрес, имя держателя карты, срок действия карты и пр.) для обработки платежей. Оператор не собирает и не хранит платежную информацию. Информация исключительно и напрямую передается соответствующему обработчику платежей</li>\r\n 	<li>лицам, осуществляющим обеспечение правовой защиты Оператора или третьих лиц при нарушении их прав либо угрозе нарушения их прав, включая нарушение законов или регулирующих документов</li>\r\n 	<li>лицам, обеспечивающим доступ пользователей к Ресурсам</li>\r\n 	<li>Любая иная персональная информация, не оговоренная выше (история посещения, используемые браузеры, операционные системы и т.д.) подлежит надежному хранению и нераспространению.</li>\r\n</ul>\r\n<strong>Как Оператор обеспечивает безопасность персональных данных?</strong>\r\nОператор защищает персональные данные, которые у него хранятся, от разглашения, полной или частичной утраты, а также несанкционированного доступа со стороны третьих лиц.\r\n\r\nДля этого Оператор использует все необходимые технические и организационные меры по обеспечению безопасности и конфиденциальности, и постоянно обновляет их с учетом последних технических разработок.\r\n\r\n<strong>Если происходит утечка персональных данных, то Оператор:</strong>\r\n<ul>\r\n 	<li>в течение 24 часов уведомляет об этом Роскомнадзор</li>\r\n 	<li>в течение 72 часов проводит собственное расследование и уведомляет Роскомнадзор о его результатах</li>\r\n</ul>\r\n<strong>Что Оператор не проверяет?</strong>\r\nОператор не может проверить и поэтому доверяет Вам в том, что вы:\r\n<ul>\r\n 	<li>обладаете полной дееспособностью</li>\r\n 	<li>предоставили собственные достоверные персональные данные</li>\r\n</ul>\r\n<strong>Как связаться с Оператором?</strong>\r\nПо любым вопросам в отношении обработки персональных данных вы можете обратиться к Оператору по e-mail <a class=\"contactsGroupMail\" href=\"mailto:clinic@handlingbetter.ru\">clinic@handlingbetter.ru</a>\r\n\r\nПри обращении укажите свое имя и контакты для обратной связи.\r\n\r\nОператор ответит на ваше обращение не позднее 10 рабочих дней с момента его получения.\r\n\r\n<strong>Изменение Политики</strong>\r\nОператор может обновить условия Политики на основании следующего:\r\n<ul>\r\n 	<li>Изменения в законодательстве</li>\r\n 	<li>Введение новых технологий или методов обработки персональных данных</li>\r\n 	<li>Изменения в структуре или бизнес-процессах Оператора</li>\r\n 	<li>Внедрение новых продуктов или услуг, которые требуют обновления подходов к обработке персональных данных</li>\r\n 	<li>Обратная связь от пользователей или изменения в политике конфиденциальности партнеров Оператора</li>\r\n</ul>\r\nОператор будет направлять уведомления об изменениях Политики в случае, если такие изменения являются существенными, доступными способами.','Политика конфиденциальности','','inherit','closed','closed','','3-revision-v1','','','2025-09-10 07:15:52','2025-09-10 04:15:52','',3,'https://center.handlingbetter.ru/?p=350',0,'revision','',0),(354,1,'2025-09-11 16:32:57','2025-09-11 13:32:57','','Зависимость','','inherit','closed','closed','','213-revision-v1','','','2025-09-11 16:32:57','2025-09-11 13:32:57','',213,'https://center.handlingbetter.ru/?p=354',0,'revision','',0),(355,1,'2025-09-1