_value\";s:0:\"\";s:9:\"maxlength\";s:0:\"\";s:11:\"placeholder\";s:0:\"\";s:7:\"prepend\";s:0:\"\";s:6:\"append\";s:0:\"\";}','Ссылка','link','publish','closed','closed','','field_697c275dea89a','','','2026-01-30 06:38:00','2026-01-30 03:38:00','',550,'https://center.handlingbetter.ru/?post_type=acf-field&#038;p=555',3,'acf-field','',0),(556,1,'2026-01-30 06:39:12','2026-01-30 03:39:12','','1','','inherit','','closed','','1-4','','','2026-01-30 06:39:12','2026-01-30 03:39:12','',547,'https://center.handlingbetter.ru/wp-content/uploads/2026/01/1.jpg',0,'attachment','image/jpeg',0),(557,1,'2026-01-30 06:39:18','2026-01-30 03:39:18','','Акции','','inherit','closed','closed','','547-revision-v1','','','2026-01-30 06:39:18','2026-01-30 03:39:18','',547,'https://center.handlingbetter.ru/?p=557',0,'revision','',0),(558,1,'2026-01-30 09:24:55','2026-01-30 06:24:55','','Акции','','inherit','closed','closed','','547-revision-v1','','','2026-01-30 09:24:55','2026-01-30 06:24:55','',547,'https://center.handlingbetter.ru/?p=558',0,'revision','',0),(559,1,'2026-01-30 09:28:07','2026-01-30 06:28:07','<p class=\"p1\">Разобраться вместе с врачом, что с вами происходит, получить «второе мнение» по вашей ситуации и понять, насколько срочно нужен очный прием.</p>\r\n<p class=\"p1\">Про преимущества и ограничения онлайн-консультаций подробно <a href=\"https://center.handlingbetter.ru/online/\">написали <span class=\"s1\">здесь</span>.</a></p>\r\n<p class=\"p1\">Сроки акции: с 1 февраля по 31 декабря 2026 года.</p>\r\n<p class=\"p1\"><i>*Кроме приемов у Елизаветы Федоровой и Екатерины Карташевой</i>.</p>','Скидка&nbsp;15% на&nbsp;онлайн-консультации у&nbsp;неврологов и&nbsp;психиатров','','trash','closed','closed','','15-na-onlayn__trashed','','','2026-02-09 09:23:10','2026-02-09 06:23:10','',0,'https://center.handlingbetter.ru/?page_id=559',0,'page','',0),(560,1,'2026-01-30 09:28:07','2026-01-30 06:28:07','<p class=\"p1\">Разобраться вместе с врачом, что с вами происходит, получить «второе мнение» по вашей ситуации и понять, насколько срочно нужен очный прием.</p>\r\n<p class=\"p1\">Про преимущества и ограничения онлайн-консультаций подробно <a href=\"https://center.handlingbetter.ru/online/\">написали <span class=\"s1\">здесь</span>.</a></p>\r\n<p class=\"p1\">Сроки акции: с 1 февраля по 31 декабря 2026 года.</p>\r\n<p class=\"p1\"><i>*Кроме приемов у Елизаветы Федоровой и Екатерины Карташевой</i>.</p>','Скидка 15% на онлайн-консультации у неврологов и психиатров','','inherit','closed','closed','','559-revision-v1','','','2026-01-30 09:28:07','2026-01-30 06:28:07','',559,'https://center.handlingbetter.ru/?p=560',0,'revision','',0),(561,1,'2026-01-30 09:28:30','2026-01-30 06:28:30','<p class=\"p1\">Разобраться вместе с врачом, что с вами происходит, получить «второе мнение» по вашей ситуации и понять, насколько срочно нужен очный прием.</p>\r\n<p class=\"p1\">Про преимущества и ограничения онлайн-консультаций подробно <a href=\"https://center.handlingbetter.ru/online/\">написали <span class=\"s1\">здесь</span>.</a></p>\r\n<p class=\"p1\">Сроки акции: с 1 февраля по 31 декабря 2026 года.</p>\r\n<p class=\"p1\"><i>*Кроме приемов у Елизаветы Федоровой и Екатерины Карташевой</i>.</p>','Скидка&nbsp;15% на&nbsp;онлайн-консультации у&nbsp;неврологов и&nbsp;психиатров','','inherit','closed','closed','','559-revision-v1','','','2026-01-30 09:28:30','2026-01-30 06:28:30','',559,'https://center.handlingbetter.ru/?p=561',0,'revision','',0),(562,1,'2026-01-30 09:28:50','2026-01-30 06:28:50','','Акции','','inherit','closed','closed','','547-revision-v1','','','2026-01-30 09:28:50','2026-01-30 06:28:50','',547,'https://center.handlingbetter.ru/?p=562',0,'revision','',0),(563,1,'2026-01-30 09:41:50','2026-01-30 06:41:50','','15','','inherit','','closed','','15','','','2026-01-30 09:41:50','2026-01-30 06:41:50','',547,'https://center.handlingbetter.ru/wp-content/uploads/2026/01/15.jpg',0,'attachment','image/jpeg',0),(564,1,'2026-01-30 09:41:55','2026-01-30 06:41: